// Declare a buffer that will be used for all of the input, output,
// intermediate tensors, and allocated variables.
uint8_t tensor_arena[kTensorArenaSize];

// Instantiate an ErrorReporter, which is used to report errors.
tflite::MicroErrorReporter micro_error_reporter;
// Create an area where allocated objects can live in memory.
// This should be long-lived (it doesn't need to be re-allocated every
// time we perform inference).
tflite::MicroMutableOpResolver<3> mutable_op_resolver;

// Model variable.
const tflite::Model* model = nullptr;
TfLiteTensor* model_input = nullptr;
TfLiteTensor* model_output = nullptr;

// Create an interpreter to run the model with.
static tflite::MicroInterpreter static_interpreter(
    model,  // Pointer to the model loaded in by the `LoadModel` function.
    mutable_op_resolver,  // The op resolver.
    tensor_arena,  // Tensor arena where memory for tensors is allocated.
    kTensorArenaSize,  // Size of the tensor arena.
    &micro_error_reporter);  // Error reporter.
tflite::MicroInterpreter* interpreter = &static_interpreter;

// Define variables to hold input and output data.
const int sensorDataLength = 3;  
float sensor_data[sensorDataLength];
uint8_t classification_result[3];

// Sensor object for the Adafruit TCS34725 color sensor.
Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_700MS, TCS34725_GAIN_1X);

void setup() {
  // Initialize serial communication.
  Serial.begin(9600);

  // Initialize the error reporter. This is used to report errors encountered during model inference.
  while (!Serial);  // Wait until serial console is available.

  // Initialize the color sensor.
  if (tcs.begin()) {
    Serial.println("Color Sensor found.");
  } else {
    Serial.println("No Color Sensor found, check your connections.");
    while (1);
  }

  // Load the model into memory.
  model = tflite::GetModel(g_model);

  // Ensure that model loading was successful.
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version mismatch!");
    return;
  }

  // Obtain pointers to the input and output tensors from the model.
  TfLiteRegistration* registration = nullptr;  // Placeholder for TensorFlow Lite tensor registration.

  model_input = interpreter->input(0);
  model_output = interpreter->output(0);

  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Tensor allocation failed!");
    return;
  }

  // Print input and output details.
  const char* input_name = interpreter->GetInputName(0);
  const int32_t input_dims[3] = {model_input->dims->data}[0],
               input_size = model_input->bytes / sizeof(float);

  Serial.print("Input tensor name: '"); Serial.print(input_name); Serial.println("'");
  Serial.print("shape: ");
  for (int i = 0; i < interpreter->inputs()->size(); ++i) {
    TfLiteIntArray* dims = model_input->dims;
    int array_size = dims->size;
    for (int j = 0; j < array_size; ++j) {
      Serial.print(dims->data[j]);
      if (j < array_size - 1) Serial.print("x");
    }
    Serial.println("");
  }

  const char* output_name = interpreter->GetOutputName(0);
  const int32_t output_dims[3] = {model_output->dims->data}[0],
                output_size = model_output->bytes / sizeof(uint8_t);

  Serial.print("Output tensor name: '"); Serial.print(output_name); Serial.println("'");
  Serial.print("shape: ");
  for (int i = 0; i < interpreter->outputs()->size(); ++i) {
    TfLiteIntArray* dims = model_output->dims;
    int array_size = dims->size;
    for (int j = 0; j < array_size; ++j) {
      Serial.print(dims->data[j]);
      if (j < array_size - 1) Serial.print("x");
    }
    Serial.println("");
  }

  // Resolve all the operators needed by this model.
  if (TfLiteInterpreterOptionsAddCustomOp(
      interpreter->options(), tflite::Register_DEQUANTIZE()) != kTfLiteOk) {
    Serial.println("Error adding custom op.");
    return;
  }
}

void loop() {
  // Initialize a new frame for capturing RGB values.
  tcs.setInterrupt(false);  // Disable interrupts.

  delay(60);  // Delay to allow the sensor time to capture data.

  uint16_t clear, red, green, blue;
  tcs.getRawData(&red, &green, &blue, &clear);

  // Convert raw values to normalized floats for model input.
  float r = red / (float) clear;
  float g = green / (float) clear;
  float b = blue / (float) clear;

  sensor_data[0] = r;
  sensor_data[1] = g;
  sensor_data[2] = b;

  // Copy the input data into the tensor.
  memcpy(model_input->data.f, sensor_data, sizeof(sensor_data));

  // Run inference.
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    Serial.println("Error invoking!");
    return;
  }

  // Process the model's output tensor(s).
  memcpy(classification_result, model_output->data.uint8, sizeof(classification_result));

  // Classify based on the highest probability.
  uint8_t max_index = 0;
  for (int i = 1; i < 3; ++i) {
    if (classification_result[i] > classification_result[max_index]) {
      max_index = i;
    }
  }

  // Output the classification result as a Unicode emoji via serial.
  switch(max_index) {
    case 0:
      Serial.println("🍎");  // Apple
      break;
    case 1:
      Serial.println("🍌");  // Banana
      break;
    case 2:
      Serial.println("🍊");  // Orange
      break;
  }

  delay(1000);  // Delay before the next reading.
}
