  while (!Serial);

  // Initialize the color sensor
  if (tcs.begin()) {
    Serial.println("Found color sensor");
  } else {
    Serial.println("No color sensor found ... check your connections");
    while (1); // Halt program, no sensor present
  }

  // Load model into memory
  model = tflite::GetModel(model_tflite);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match TensorFlow Lite runtime.");
    while (1);
  }

  // Set up an op resolver
  static tflite::AllOpsResolver resolver;

  // Create interpreter with tensor arena, model and resolver
  const tflite::MicroInterpreterOptions options;
  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena, TENSOR_ARENA_SIZE, error_reporter);

  // Allocate memory from the tensor_arena for the model's tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    Serial.println("AllocateTensors() failed");
    while (1);
  }
}

void loop() {
  // Read color data from sensor
  uint16_t clear, red, green, blue;
  tcs.getRawData(&red, &green, &blue, &clear);

  // Normalize and scale to [0, 1]
  float r = red / (float)clear;
  float g = green / (float)clear;
  float b = blue / (float)clear;

  input_data[0] = r;
  input_data[1] = g;
  input_data[2] = b;

  // Copy the data to the model's input tensor
  TfLiteTensor* input_tensor = interpreter->input(0);
  if (input_tensor->type == kTfLiteFloat32) {
    float* input_ptr = input_tensor->data.f;
    memcpy(input_ptr, input_data, sizeof(input_data));
  }

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    Serial.println("Invoke failed");
    return;
  }

  // Get the model's output tensor and print classification result
  TfLiteTensor* output_tensor = interpreter->output(0);
  if (output_tensor->type == kTfLiteUInt8) {
    uint8_t* output_ptr = output_tensor->data.uint8;

    float max_score = -1.0;
    int class_id = 0;
    for (int i = 0; i < 3; ++i) { // Assuming the model outputs a one-hot encoded array
      if (output_ptr[i] > max_score) {
        max_score = output_ptr[i];
        class_id = i;
      }
    }

    switch (class_id) {
      case 0:
        Serial.println("🍎 Apple");
        break;
      case 1:
        Serial.println("🍌 Banana");
        break;
      case 2:
        Serial.println("🍊 Orange");
        break;
      default:
        Serial.println("Unknown class");
    }
  }

  delay(1000); // Delay for demonstration purposes
}
