#include <Arduino.h>
#include "TensorFlowLite.h"
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "model.h" // Your generated model header

// Define the tensor arena size
constexpr int kTensorArenaSize = 2048;

// Create an area of memory to use for input, output, and intermediate arrays.
uint8_t tensor_arena[kTensorArenaSize];

// Global variables for TensorFlow Lite Micro inference
tflite::ErrorReporter* error_reporter;
const tflite::Model* model;
tflite::MicroInterpreter* interpreter;

void setup() {
  // Start serial communication
  Serial.begin(9600);

  // Create an error reporter object, needed by the micro-frontend layer
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load model data from model.h into a buffer
  extern const unsigned char model[];
  model = tflite::GetModel(model);

  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match Tensorflow runtime.");
    while (1); // Halt execution
  }

  // Select an operation resolver
  static tflite::ops::micro::AllOpsResolver resolver;

  // Create an interpreter to run the model with
  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

  // Allocate memory from the tensor arena for the model's tensors.
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("AllocateTensors() failed");
    while (1);
  }

  // Initialize the color sensor
  Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

  if (tcs.begin()) {
    Serial.println("Color sensor found");
  } else {
    Serial.println("No TCS34725 found ... check your connections");
    while (1); // Halt execution if sensor not detected
  }
}

void loop() {
  classifyColor();
  delay(1000); // Wait for a second before the next read
}

void classifyColor() {
  Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

  uint16_t clear, red, green, blue;
  tcs.getRawData(&red, &green, &blue, &clear);

  float normalizedRed = (float)red / clear;
  float normalizedGreen = (float)green / clear;
  float normalizedBlue = (float)blue / clear;

  // Copy data to the input tensor
  TfLiteTensor* input_tensor = interpreter->input(0);
  float* input_data = input_tensor->data.f;

  input_data[0] = normalizedRed;
  input_data[1] = normalizedGreen;
  input_data[2] = normalizedBlue;

  // Run inference
  if (interpreter->Invoke() == kTfLiteOk) {
    TfLiteTensor* output_tensor = interpreter->output(0);
    const uint8_t* output_data = reinterpret_cast<const uint8_t*>(output_tensor->data.uint8);

    int class_idx = std::distance(output_data, std::max_element(output_data, output_data + 3));

    switch (class_idx) {
      case 0:
        Serial.println("🍎"); // Apple emoji
        break;
      case 1:
        Serial.println("🍌"); // Banana emoji
        break;
      case 2:
        Serial.println("🍊"); // Orange emoji
        break;
    }
  } else {
    Serial.println("Invoke failed!");
  }
}
