#include "TensorFlowLite.h"
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "tensorflow/lite/version.h"

// Include sensor and I/O libraries
#include "Adafruit_APDS9960.h"
#include "Wire.h"
#include "model.h"  // Ensure the path to model file is correct

#define TENSOR_ARENA_SIZE 2048  // Tensor arena size for memory allocation

// Define error reporter, model pointer, interpreter, and input tensor
tflite::ErrorReporter* error_reporter = nullptr;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;
TfLiteTensor* input = nullptr;

// Tensor arena for TensorFlow Lite Micro
uint8_t tensor_arena[TENSOR_ARENA_SIZE];

Adafruit_APDS9960 apds;

void setup() {
  // Initialize serial communication
  Serial.begin(9600);

  // Setup error reporter for logging
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load the model
  model = tflite::GetModel(model_data);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match TensorFlow Lite runtime.");
    return;
  }

  // Set up OpResolver and interpreter
  static tflite::AllOpsResolver resolver;
  static tflite::MicroInterpreter intp(model, resolver, tensor_arena,
                                       TENSOR_ARENA_SIZE, error_reporter);

  interpreter = &intp;

  // Allocate memory for tensors
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    return;
  }

  // Get input tensor details
  input = interpreter->input(0);

  // Initialize the APDS9960 Color Sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize color sensor.");
    return;
  }
}

void loop() {
  uint16_t clear, red, green, blue;

  // Check if there's new data available from the color sensor
  if (apds.readColor(red, green, blue, clear)) {

    // Normalize RGB values based on dataset statistics and store in input tensor
    input->data.f[0] = red / 1023.0 * 0.636;      // Normalize to max value found in dataset
    input->data.f[1] = green / 1023.0 * 0.292;
    input->data.f[2] = blue / 1023.0 * 0.25;

    // Run inference
    if (interpreter->Invoke() == kTfLiteOk) {
      const TfLiteTensor* output = interpreter->output(0);

      // Process the output to determine class index with highest confidence
      int class_idx = 0;
      float max_confidence = -1.0;

      for (int i = 0; i < 3; ++i) {  // Assuming there are 3 classes: Apple, Banana, Orange
        if (output->data.uint8[i] > max_confidence) {
          max_confidence = output->data.uint8[i];
          class_idx = i;
        }
      }

      // Map the class index to emoji and print to serial
      const char* emojis[] = {"🍎", "🍌", "🍊"};
      Serial.println(emojis[class_idx]);
    } else {
      Serial.println("Inference failed.");
    }
  }

  delay(1000); // Delay between readings for stability
}
