#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/version.h>
#include "model.h"
#include <ArduinoBLE.h>

// Define tensor arena size
constexpr int kTensorArenaSize = 1024;
uint8_t tensor_arena[kTensorArenaSize];

// Declare TensorFlow Lite variables
tflite::ErrorReporter* error_reporter = nullptr;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;

// Declare input and output pointers
float* input_ptr = nullptr;
uint8_t* output_ptr = nullptr;

void setup() {
  // Initialize serial communication
  Serial.begin(9600);

  // Initialize BLE for communication (if needed)
  if (!BLE.begin()) {
    Serial.println("Starting Bluetooth failed!");
    while (1);
  }

  // Create an ErrorReporter object
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load the model into a flat buffer
  model = tflite::GetModel(g_model);

  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match TensorFlow Lite runtime.");
    while (1);
  }

  // Use AllOpsResolver to ensure all operators in the model are available
  static tflite::AllOpsResolver resolver;

  // Set up an area of memory to use for input, output, and intermediate arrays.
  // The size needed is defined by the model itself.
  static uint8_t tensor_arena[kTensorArenaSize];
  tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

  // Allocate memory from the tensor_arena for the model's tensors
  interpreter.AllocateTensors();

  // Obtain pointers to the model's input and output tensors
  input_ptr = interpreter.input(0)->data.f;
  output_ptr = interpreter.output(0)->data.uint8;

  // Initialize any other peripherals or sensors here
}

void loop() {
  // Simulate sensor reading (replace with actual sensor code)
  float red = 0.6, green = 0.2, blue = 0.15; // Example RGB values

  // Copy the input data into the tensor's buffer
  input_ptr[0] = red;
  input_ptr[1] = green;
