// Define tensor arena size and ensure it fits within memory constraints of the device
constexpr int kTensorArenaSize = 1024;
uint8_t tensor_arena[kTensorArenaSize];

// Create error reporter instance for logging errors
static tflite::MicroErrorReporter micro_error_reporter;

// Declare a pointer to store the model, and a flat buffer interpreter
const tflite::Model* model;
tflite::MicroInterpreter* interpreter;

// Define pointers for input and output tensors
float* input_ptr;
uint8_t* output_ptr;

void setup() {
  // Begin serial communication at specified baud rate
  Serial.begin(9600);

  // Wait until the serial connection is established (useful for boards like Nano 33 BLE)
  while (!Serial) {}

  // Set up TensorFlow Lite Micro infrastructure
  static tflite::MicroOpResolver<6> resolver; // Adjust number of operations as needed

  // Map model into a usable data structure
  model = tflite::GetModel(g_model);

  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model provided is schema version mismatch!");
    while (true); // Halt execution on error
  }

  // Pull in only the operation resolver implementations we need
  static tflite::MicroInterpreter static_interpreter(
      model, resolver, tensor_arena, kTensorArenaSize, &micro_error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory from the tensor arena for the model's tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    Serial.println("Tensor allocation failed");
    while (true); // Halt execution on error
  }

  // Obtain pointers to input and output tensors
  input_ptr = interpreter->input(0)->data.f;
  output_ptr = interpreter->output(0)->data.uint8;

  // Any additional setup for BLE or other components can be added here

}

void loop() {
  // Simulate sensor data acquisition. Replace this with actual color sensor readings.
  float redValue = 0.522f;    // Example red value
  float greenValue = 0.261f;  // Example green value
  float blueValue = 0.217f;   // Example blue value

  // Copy the input data into the model's input tensor
  *input_ptr++ = redValue;
  *input_ptr++ = greenValue;
  *input_ptr++ = blueValue;

  // Run inference using the interpreter
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    Serial.println("Model invocation failed");
    return; // Exit loop iteration on error
  }

  // Process and display the output. Assuming single-class classification.
  uint8_t class_index = *output_ptr;

  // Map class index to a human-readable name (assuming three classes: Apple, Banana, Orange)
  const char* object_name;
  switch (class_index) {
    case 0:
      object_name = "Apple";
      break;
    case 1:
      object_name = "Banana";
      break;
    case 2:
      object_name = "Orange";
      break;
    default:
      Serial.println("Unknown class");
      return; // Exit loop iteration on error
  }

  // Output the result via serial communication, using Unicode emoji for demonstration
  Serial.print("Detected: ");
  if (object_name[0] == 'A') {
    Serial.write(0x1F34E); // Apple emoji
  } else if (object_name[0] == 'B') {
    Serial.write(0x1F34C); // Banana emoji
  } else if (object_name[0] == 'O') {
    Serial.write(0x1F34A); // Orange emoji
  }
  Serial.println(" " + String(object_name));

  // Introduce a delay to prevent spamming the serial output
  delay(1000);
}
