#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "tensorflow/lite/version.h"
#include "model.h"

#include <Adafruit_TCS34725.h>

// Define the tensor arena size as specified in the application specifications
constexpr int kTensorArenaSize = 2048;

// Create a buffer to hold the model within ROM.
uint8_t tensor_arena[kTensorArenaSize];

// Declare variables for TensorFlow Lite Micro components
tflite::ErrorReporter* error_reporter;
const tflite::Model* model;
tflite::MicroInterpreter* interpreter;

// Declare input and output tensors
TfLiteTensor* input;
TfLiteTensor* output;

Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

void setup() {
  // Initialize serial communication for debugging and output
  Serial.begin(9600);

  // Initialize the color sensor
  if (!tcs.begin()) {
    Serial.println("No TCS34725 found ... check your connections");
    while (1); // Halt if no sensor is found
  }

  // Set up logging for error reporting
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Map the model into a usable data structure
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    TF_LITE_REPORT_ERROR(error_reporter, "Model provided is schema version %d not equal supported version %d.",
                         model->version(), TFLITE_SCHEMA_VERSION);
    return;
  }

  // Create an OpResolver for the micro interpreter
  static tflite::ops::micro::AllOpsResolver resolver;

  // Set up tensor arena for memory allocation
  static uint8_t tensor_arena[kTensorArenaSize];
  tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

  interpreter = &static_interpreter;

  // Allocate tensors and check for successful memory allocation
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Allocate Tensors Failed");
    return;
  }

  // Get pointers to the input and output tensors
  input = interpreter->input(0);
  output = interpreter->output(0);
}

void loop() {
  // Variables to store color sensor readings
  uint16_t clear, red, green, blue;

  // Read values from the TCS34725 color sensor
  tcs.getRawData(&red, &green, &blue, &clear);

  // Convert sensor readings to float and normalize (0-1 range)
  input->data.f[0] = static_cast<float>(red) / clear;
  input->data.f[1] = static_cast<float>(green) / clear;
  input->data.f[2] = static_cast<float>(blue) / clear;

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed");
    return;
  }

  // Process the output and determine classification based on highest value in output tensor
  uint8_t maxIndex = 0;
  float maxValue = output->data.uint8[0];

  for (int i = 1; i < output->dims->data[1]; ++i) {
    if (output->data.uint8[i] > maxValue) {
      maxValue = output->data.uint8[i];
      maxIndex = i;
    }
  }

  // Output the classification result using Unicode emojis
  switch(maxIndex) {
    case 0:
      Serial.println("🍏");  // Apple emoji for class 0
      break;
    case 1:
      Serial.println("🍌");  // Banana emoji for class 1
      break;
    case 2:
      Serial.println("🍊");  // Orange emoji for class 2
      break;
    default:
      Serial.println("Unknown");
  }

  delay(1000); // Wait before next reading
}
