#include "model.h"
#include <TensorFlowLite.h>
#include <Adafruit_TCS34725.h>

// Declaration of TensorFlow Lite Micro variables.
tflite::ErrorReporter* error_reporter;
const tflite::Model* model;
TfLiteInterpreter* interpreter;
uint8_t tensor_arena[1024];

// Variables for input and output processing
float input_data[3];
uint8_t output_data[3];
Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

void setup() {
  // Initialize Serial communication for debugging and results.
  Serial.begin(9600);

  // TensorFlow Lite Micro Initialization
  error_reporter = tflite::MicroErrorReporter();
  model = tflite::GetModel(model_data);

  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter->Report("Model schema version doesn't match.");
    while (true);
  }

  static tflite::ops::micro::AllOpsResolver resolver;
  const TfLiteAllocationType allocator_type = kTfLiteMmapRo;
  static uint8_t tensor_arena[1024];

  interpreter = new TfLiteInterpreter(model, resolver, tensor_arena, sizeof(tensor_arena), error_reporter);

  if (interpreter->AllocateTensors() != kTfLiteOk) {
    error_reporter->Report("Failed to allocate tensors.");
    while (true);
  }

  // Sensor setup
  if (!tcs.begin()) {
    Serial.println("No TCS34725 found ... check your connections");
    while (1);  // Infinite loop on failure.
  }

  // Preprocessing: Normalize sensor data based on dataset statistics for input tensor
}

void loop() {
  // Preprocessing: Read color values from the sensor and normalize them
  uint16_t clear, red, green, blue;

  tcs.getRawData(&red, &green, &blue, &clear);

  float r = (float)red / clear * 255.0;
  float g = (float)green / clear * 255.0;
  float b = (float)blue / clear * 255.0;

  // Normalize using dataset statistics
  input_data[0] = (r - 0.5) / 0.136; // Normalizing Red channel
  input_data[1] = (g - 0.182) / 0.11;  // Normalizing Green channel
  input_data[2] = (b - 0.167) / 0.083; // Normalizing Blue channel

  // Copy data to the model's input tensor.
  float* input_ptr = interpreter->input(0)->data.f;
  for (size_t i = 0; i < 3; ++i) {
    input_ptr[i] = input_data[i];
  }

  // Inference
  if (interpreter->Invoke() != kTfLiteOk) {
    error_reporter->Report("Invoke failed.");
    while (true);
  }

  // Postprocessing: Retrieve and interpret the output tensor.
  const TfLiteTensor* output_tensor = interpreter->output(0);

  memcpy(output_data, output_tensor->data.uint8, sizeof(output_data));

  int predicted_class_index = 0;
  uint8_t max_value = output_data[0];
  for (int i = 1; i < 3; ++i) {
    if (output_data[i] > max_value) {
      max_value = output_data[i];
      predicted_class_index = i;
    }
  }

  // Output the classification result
  const char* class_labels[] = {"Apple", "Banana", "Orange"};
  Serial.print("Predicted: ");
  Serial.println(class_labels[predicted_class_index]);

  delay(1000);  // Delay to control inference rate.
}
