#include <TensorFlowLite.h> // Base library for TensorFlow Lite Micro
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/kernels/micro_ops.h"
#include "tensorflow/lite/micro/memory_helpers.h"  
#include "tensorflow/lite/schema/schema_generated.h"
#include "model.h"

#include <Adafruit_TCS34725.h>

// Define the tensor arena size
constexpr int kTensorArenaSize = 1024;
uint8_t tensor_arena[kTensorArenaSize];

// Variables for TensorFlow Lite Micro
tflite::ErrorReporter* error_reporter;
const tflite::Model* model;
TfLiteInterpreter* interpreter;

// Function to initialize the TFLite components
void setup_tflite() {
  // Initialize the error reporter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Map the model into a usable data structure
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    TF_LITE_REPORT_ERROR(error_reporter, "Model provided is schema version %d not equal supported version %d.",
                         model->version(), TFLITE_SCHEMA_VERSION);
    return;
  }

  // Initialize the Op resolver
  static tflite::ops::micro::AllOpsResolver resolver;

  // Create an interpreter to run inference with
  const int tensor_arena_size = kTensorArenaSize;
  static uint8_t tensor_arena[tensor_arena_size];
  static tflite::MicroInterpreter static_interpreter(
      model, resolver, tensor_arena, tensor_arena_size, error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory from the tensor_arena for the model's tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed");
    return;
  }

  // Retrieve pointers to the input and output tensors
  TfLiteTensor* input_tensor = interpreter->input(0);
}

// Setup function for initializing sensors and TFLite components
void setup() {
  Serial.begin(9600);

  // Initialize the color sensor
  Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);
  if (tcs.begin()) {
    Serial.println("Color sensor found");
  } else {
    Serial.println("No color sensor found");
    while (1) delay(10); // Halt
  }

  setup_tflite();
}

// Loop function for continuous inference and classification
void loop() {
  // Read the color values from the sensor
  uint16_t clear, red, green, blue;
  tcs.getRawData(&red, &green, &blue, &clear);

  float r = red / (float)clear;
  float g = green / (float)clear;
  float b = blue / (float)clear;

  // Preprocess the input data
  const int tensor_index = interpreter->inputs()[0];
  TfLiteTensor* tensor = interpreter->tensor(tensor_index);

  // Normalize and scale the RGB values according to dataset statistics
  tensor->data.f[0] = (r - 0.5) / 0.028464634416673053;
  tensor->data.f[1] = (g - 0.23716901408450702) / 0.021283115987959598;
  tensor->data.f[2] = (b - 0.200056338028169) / 0.019259793296579324;

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed");
    return;
  }

  // Postprocess the output
  const int output_tensor_index = interpreter->outputs()[0];
  TfLiteTensor* output_tensor = interpreter->tensor(output_tensor_index);

  // Find the class with the highest probability
  float* output_data = output_tensor->data.f;
  int max_index = 0;
  for (int i = 1; i < 3; ++i) {
    if (output_data[i] > output_data[max_index]) {
      max_index = i;
    }
  }

  // Output the result
  switch (max_index) {
    case 0:
      Serial.println("🍎"); // Apple
      break;
    case 1:
      Serial.println("🍌"); // Banana
      break;
    case 2:
      Serial.println("🍊"); // Orange
      break;
  }

  delay(1000); // Delay between readings
}
