```cpp
#include <TensorFlowLite.h>  // Base library
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/kernels/kernel_util.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/schema/schema_generated.h>
#include <tensorflow/lite/version.h>

#include "model.h"  // Model generated from TensorFlow Lite
#include "Adafruit_TCS34725.h"

// TensorArena size defined according to model requirements
constexpr int tensor_arena_size = 1024;
uint8_t tensor_arena[tensor_arena_size];

// Define error reporter
static tflite::MicroErrorReporter micro_error_reporter;

// Define task allocator for TensorFlow Lite
TfLiteStatus AllocateTensor(void* buffer, size_t bytes, const char* name) {
    if (buffer == nullptr) {
        TF_LITE_REPORT_ERROR(&micro_error_reporter,
                             "Failed to allocate memory for tensor %s\n", name);
        return kTfLiteError;
    }
    return kTfLiteOk;
}

// Define input and output tensors
static tflite::MicroInterpreter static_interpreter(
    model, tflite::ops::micro::AllOpsResolver(), tensor_arena,
    tensor_arena_size, &micro_error_reporter, AllocateTensor);

tflite::MicroInterpreter* interpreter = &static_interpreter;

// Declare Adafruit_TCS34725 color sensor
Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

void setup() {
    Serial.begin(9600);
    while (!Serial);  // Wait for serial port to connect

    if (tcs.begin()) {
        Serial.println("TCS34725 color sensor found.");
    } else {
        Serial.println("No TCS34725 sensor found ... check your connections");
        while (1) delay(10);
    }

    // Allocate memory for tensors
    TfLiteStatus allocate_status = interpreter->AllocateTensors();
    if (allocate_status != kTfLiteOk) {
        TF_LITE_REPORT_ERROR(&micro_error_reporter,
                             "Tensor allocation failed\n");
        while (1) delay(10);  // Halt on error
    }

    // Retrieve model input tensor details
    TfLiteTensor* input_tensor = interpreter->input(0);
}

void loop() {
    uint16_t clear, red, green, blue;

    if (!tcs.getRawData(&red, &green, &blue, &clear)) {
        Serial.println("Error reading data from TCS34725 sensor");
        return;
    }

    // Normalize color values
    float r = static_cast<float>(red) / clear;
    float g = static_cast<float>(green) / clear;
    float b = static_cast<float>(blue) / clear;

    // Prepare input tensor data
    TfLiteTensor* input_tensor = interpreter->input(0);
    float* input_data = input_tensor->data.f;

    // Normalize according to dataset statistics
    input_data[0] = (r - 0.5) / 0.028464634416673053;  // Red
    input_data[1] = (g - 0.23716901408450702) / 0.021283115987959598;  // Green
    input_data[2] = (b - 0.200056338028169) / 0.019259793296579324;  // Blue

    // Invoke the interpreter
    TfLiteStatus invoke_status = interpreter->Invoke();
    if (invoke_status != kTfLiteOk) {
        TF_LITE_REPORT_ERROR(&micro_error_reporter, "Invoke failed\n");
        return;
    }

    // Retrieve model output tensor
    TfLiteTensor* output_tensor = interpreter->output(0);
    uint8_t* output_data = output_tensor->data.uint8;

    // Determine the class with the highest probability
    int predicted_class = 0;
    for (int i = 1; i < 3; ++i) {
        if (output_data[i] > output_data[predicted_class]) {
            predicted_class = i;
        }
    }

    // Output result via serial using Unicode emojis
    switch (predicted_class) {
        case 0:
            Serial.println("\xF0\x9F\x8D\xA3");  // Apple emoji
            break;
        case 1:
            Serial.println("\xF0\x9F\x98\x85");  // Banana emoji
            break;
        case 2:
            Serial.println("\xF0\x9F\x8C\xBA");  // Orange emoji
            break;
    }

    delay(1000);  // Delay before next reading
}
