#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/kernels/micro_ops.h>
#include <tensorflow/lite/schema/schema_generated.h>
#include <tensorflow/lite/version.h>
#include "model.h"

// Ensure the correct sensor library for the Arduino Nano 33 BLE Sense
#include <Arduino_LSM9DS1.h>

namespace {
constexpr int kTensorArenaSize = 1024;
}  // namespace

uint8_t tensor_arena[kTensorArenaSize];

// Create an ErrorReporter object to report errors
tflite::ErrorReporter* error_reporter = nullptr;

// Instantiate the model
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  Serial.println("Model provided is schema version incompatible.");
  while (1) {}
}

TfLiteStatus allocate_tensors(tflite::MicroInterpreter& interpreter);

void setup() {
  // Initialize serial communication
  Serial.begin(9600);

  // Initialize the IMU
  if (!IMU.begin()) {
    Serial.println("Failed to initialize IMU!");
    while (1);
  }

  // Set up error reporter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Map model into a usable data structure
  static tflite::MicroInterpreter static_interpreter(
      model, tflite::AllOpsResolver(), tensor_arena, kTensorArenaSize,
      error_reporter);

  interpreter = &static_interpreter;

  if (allocate_tensors(*interpreter) != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1);
  }
}

void loop() {
  // Read from the IMU color sensor
  float red, green, blue;
  if (!IMU.colorAvailable()) {
    return;  // Wait for data to be available
  }

  IMU.readColor(red, green, blue);

  // Preprocess and normalize the input values as required by the model
  float normalizedRed = (red - 0.5) / 0.136;   // Normalizing around dataset mean and std deviation
  float normalizedGreen = (green - 0.182) / 0.121;
  float normalizedBlue = (blue - 0.167) / 0.083;

  // Copy the input data to the model's input tensor
  TfLiteTensor* input_tensor =
      interpreter->input(0);  // Get the model's input tensor
  if (input_tensor->type == kTfLiteFloat32) {
    float* input_data = input_tensor->data.f;
    input_data[0] = normalizedRed;
    input_data[1] = normalizedGreen;
    input_data[2] = normalizedBlue;
  }

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    Serial.println("Failed to invoke!");
    return;
  }

  // Get the output data from the model's output tensor
  TfLiteTensor* output_tensor =
      interpreter->output(0);  // Get the model's output tensor
  const uint8_t* output_data = output_tensor->data.uint8;

  int max_confidence_index = -1;
  float max_confidence_value = -1.0;

  for (int i = 0; i < 3; ++i) {
    if (output_data[i] > max_confidence_value) {
      max_confidence_value = output_data[i];
      max_confidence_index = i;
    }
  }

  // Output the result
  const char* classes[] = {"Apple", "Banana", "Orange"};
  if (max_confidence_index >= 0 && max_confidence_index < 3) {
    Serial.print("Detected object: ");
    Serial.println(classes[max_confidence_index]);
  } else {
    Serial.println("Object not recognized");
  }

  delay(1000);  // Delay before the next reading
}

TfLiteStatus allocate_tensors(tflite::MicroInterpreter& interpreter) {
  TfLiteStatus alloc_status = interpreter.AllocateTensors();
  if (alloc_status != kTfLiteOk) {
    return alloc_status;
  }
  return kTfLiteOk;
}
