```cpp
#include <TensorFlowLite.h> // Base library
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/kernels/micro_ops.h>
#include <tensorflow/lite/micro/memory_helpers.h>

#include "model.h"  // Include the model header

// Define TensorArenaSize to allocate memory for TensorFlow Lite operations.
constexpr int TensorArenaSize = 1024;

// Allocate a tensor arena
alignas(16) uint8_t tensor_arena[TensorArenaSize];

// Declare error reporter and interpreter objects
tflite::ErrorReporter* error_reporter;
const tflite::Model* model;
tflite::MicroInterpreter* interpreter;
TfLiteTensor* input;
TfLiteTensor* output;

// Function declarations
void setupTensorFlow();
void classifyColor(float red, float green, float blue);

void setup() {
  // Initialize serial communication
  Serial.begin(9600);

  while (!Serial) {
    delay(10); // Wait for the serial port to connect.
  }

  setupTensorFlow();

  // Setup sensor (RGB color sensor)
  if (!IMU.begin()) {
    Serial.println("Failed to initialize IMU!");
    while (1);
  }
}

void loop() {
  float red, green, blue;

  // Read color from the RGB sensor
  if (IMU.colorAvailable()) {
    IMU.readColor(red, green, blue);

    classifyColor(red, green, blue);
  }

  delay(1000); // Wait before next reading
}

void setupTensorFlow() {
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load the model into a new `tflite::FlatBufferModel`
  model = tflite::GetModel(g_model);

  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model version does not match Schema");
    while (1);
  }

  // Create an AllOpsResolver
  static tflite::AllOpsResolver resolver;

  // Setup the interpreter
  static uint8_t tensor_arena[TensorArenaSize];
  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena,
                                             TensorArenaSize, error_reporter);

  // Allocate memory from the tensor_arena for the model's tensors
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1);
  }

  // Get pointers to the input and output tensors
  input = interpreter->input(0);
  output = interpreter->output(0);

  // Print model details for verification
  Serial.print("Model Name: ");
  Serial.println(model->description()->name());
}

void classifyColor(float red, float green, float blue) {
  // Ensure the input tensor is the expected size (1x3)
  if (input->dims->data[0] == 1 && input->dims->data[1] == 3) {
    // Copy RGB values into the model's input tensor
    TfLiteType type = input->type;
    if (type == kTfLiteFloat32) {
      float* buffer = input->data.f;
      buffer[0] = red;
      buffer[1] = green;
      buffer[2] = blue;
    } else {
      Serial.println("Input tensor data type mismatch!");
      return;
    }

    // Run inference
    if (interpreter->Invoke() != kTfLiteOk) {
      Serial.println("Failed to invoke interpreter");
      return;
    }

    // Process the output: interpret and display result
    const char* classes[] = {"Apple", "Banana", "Orange"};
    int predicted_class = -1;
    float max_confidence = 0.0;

    for (int i = 0; i < 3; ++i) {
      float confidence = output->data.uint8[i];
      if (confidence > max_confidence) {
        max_confidence = confidence;
        predicted_class = i;
      }
    }

    Serial.print("Classified as: ");
    Serial.println(classes[predicted_class]);
    Serial.print("Confidence: ");
    Serial.println(max_confidence);
  } else {
    Serial.println("Input tensor dimensions do not match!");
  }
}
