```cpp
#include <TensorFlowLite.h>
#include "Arduino_LSM9DS1.h"
#include "ArduinoBLE.h"
#include "Wire.h"
#include "model.h"

// Define Tensor Arena Size
constexpr int tensor_arena_size = 2048;
uint8_t tensor_arena[tensor_arena_size];

// Declare TensorFlow Lite variables
tflite::ErrorReporter* error_reporter = nullptr;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;
TfLiteTensor* input = nullptr;

// Define classification classes
constexpr char* CLASS_NAMES[] = {"Apple", "Banana", "Orange"};

void setup() {
  // Initialize Serial Communication
  Serial.begin(9600);

  // Set up error reporter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load the model into memory
  model = tflite::GetModel(model_data);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version mismatch!");
    return;
  }

  // Initialize OpResolver with default operations
  static tflite::ops::micro::AllOpsResolver resolver;

  // Allocate memory for the interpreter and tensors
  static tflite::MicroInterpreter static_interpreter(
      model, resolver, tensor_arena, tensor_arena_size, error_reporter);

  interpreter = &static_interpreter;
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    return;
  }

  // Obtain pointer to the input tensor
  input = interpreter->input(0);

  // Initialize sensors
  if (!IMU.begin()) {
    Serial.println("Failed to initialize IMU!");
    while (1);
  }
}

void loop() {
  // Read RGB color values from sensor
  float r, g, b;
  IMU.colorRGB(r, g, b);

  // Normalize the RGB values according to dataset statistics
  r = (r - 0.5) / (0.636 - 0.5);
  g = (g - 0.182) / (0.292 - 0.182);
  b = (b - 0.167) / (0.25 - 0.167);

  // Copy normalized RGB values into input tensor
  float* input_data = input->data.f;
  input_data[0] = r;
  input_data[1] = g;
  input_data[2] = b;

  // Run inference
  if (interpreter->Invoke() != kTfLiteOk) {
    Serial.println("Failed to invoke!");
    return;
  }

  // Process output tensor
  TfLiteTensor* output = interpreter->output(0);
  int predicted_class_index = -1;
  float max_score = -1.0;

  for (int i = 0; i < 3; ++i) {
    if (output->data.uint8[i] > max_score) {
      max_score = output->data.uint8[i];
      predicted_class_index = i;
    }
  }

  // Output the class name using Unicode emojis
  switch (predicted_class_index) {
    case 0:
      Serial.println("🍎");  // Apple
      break;
    case 1:
      Serial.println("🍌");  // Banana
      break;
    case 2:
      Serial.println("🍊");  // Orange
      break;
    default:
      Serial.println("Unknown");
      break;
  }

  delay(1000);
}
