  // Resolve all operators used by this model
  static tflite::AllOpsResolver resolver;

  // Create an interpreter to run the model with the tensor arena
  TfLiteStatus allocate_status = AllocateTfLiteTensorArena(tensor_arena, kTensorArenaSize);
  if (allocate_status != kTfLiteOk) {
    LogError("Failed to allocate tensor arena");
    while (true); // Halt execution
  }

  // Initialize interpreter with model, resolver, and error reporter
  TfLiteInterpreterOptions* options = nullptr;
  TfLiteInterpreterCreate(model, options, &interpreter);

  if (!interpreter) {
    LogError("Failed to create the interpreter");
    while (true); // Halt execution
  }

  // Allocate tensors with tensor arena
  allocate_status = InterpreterAllocateTensors(interpreter);
  if (allocate_status != kTfLiteOk) {
