  TfLiteTensor* input_tensor = InterpreterGetInputTensor(interpreter, 0);
  float* input_ptr = TfLiteTensorData(input_tensor);

  input_ptr[0] = red;
  input_ptr[1] = green;
  input_ptr[2] = blue;

  // Invoke the interpreter to perform inference
  if (InterpreterInvoke(interpreter) != kTfLiteOk) {
    LogError("Failed to invoke the interpreter");
    return;
