#include <Arduino.h>
#include <TensorFlowLite.h>
#include "model.h"
#include <Adafruit_TCS34725.h>
#include <Wire.h>

// Error reporting function
void error(const char* msg) {
  Serial.println(msg);
  while (1); // Halt on error
}

// Declare TensorFlow Lite variables
tflite::ErrorReporter* error_reporter;
const tflite::Model* model;
std::unique_ptr<tflite::MicroInterpreter> interpreter;

// Define tensor arena size
constexpr int kTensorArenaSize = 4096;
uint8_t tensor_arena[kTensorArenaSize];

// RGB sensor instance
Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

void setup() {
  // Initialize Serial for debugging
  Serial.begin(9600);
  while (!Serial) {
    delay(10); // Wait for serial port to connect
  }

  // Initialize the color sensor
  if (tcs.begin()) {
    Serial.println("TCS34725 color sensor found.");
  } else {
    error("No TCS34725 found ... check your connections");
  }

  // Load model and initialize TensorFlow Lite interpreter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  model = tflite::GetModel(model_tflite);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error("Model schema version does not match TensorFlow Lite runtime.");
  }

  static tflite::ops::builtin::BuiltinOpResolver resolver;
  const tflite::MicroInterpreterOptions options = {resolver, kTensorArenaSize, tensor_arena};
  interpreter.reset(tflite::MakeMicroInterpreter(model, options, error_reporter));
  if (!interpreter) {
    error("Failed to create the TensorFlow Lite interpreter.");
  }

  // Allocate memory for tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error("Tensor allocation failed");
  }
}

void loop() {
  // Read RGB values from the sensor
  float r, g, b;
  uint16_t clear;
  tcs.getRawData(&r, &g, &b, &clear);

  // Normalize RGB values to [0,1] and prepare input tensor
  float red = r / (float)clear;
  float green = g / (float)clear;
  float blue = b / (float)clear;

  float* input_data = interpreter->input(0)->data.f;
  input_data[0] = red;
  input_data[1] = green;
  input_data[2] = blue;

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    error("Inference invocation failed");
  }

  // Process output and print result
  const int* output = interpreter->output(0)->data.int32;
  switch (*output) {
    case 0:
      Serial.println("\U0001F34E"); // Apple emoji
      break;
    case 1:
      Serial.println("\U0001F34C"); // Banana emoji
      break;
    case 2:
      Serial.println("\U0001F34F"); // Orange emoji
      break;
    default:
      error("Unknown output");
  }

  delay(1000); // Run every second
}
