#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/kernels/micro_ops.h"
#include "tensorflow/lite/micro/memory_helpers.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "tensorflow/lite/version.h"

#include "model.h"  // Correctly include the model file

#include <Adafruit_TCS34725.h>  // Color sensor library
#include <Arduino_LSM9DS1.h>
#include <Wire.h>

// Define tensor arena size
constexpr int kTensorArenaSize = 4096;

// Create a memory pool to allocate the TFLM tensors
alignas(16) uint8_t tensor_arena[kTensorArenaSize];

// Declare the error reporter for logging errors
tflite::MicroErrorReporter micro_error_reporter;
const tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Model pointer and interpreter declaration
TfLiteModel* model = nullptr;
static tflite::MicroInterpreter static_interpreter;  // Used for the global interpreter object
tflite::MicroInterpreter* interpreter = &static_interpreter;

// Define tensor pointers
TfLiteTensor* input = nullptr;
TfLiteTensor* output = nullptr;

// Color sensor instance
Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

void setup() {
  Serial.begin(9600);
  while (!Serial); // Wait for the serial port to connect

  // Initialize color sensor
  if (tcs.begin()) {
    Serial.println("Color sensor initialized.");
  } else {
    Serial.println("Failed to initialize color sensor!");
    while (1);
  }

  // Load model from flash and create an interpreter
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match TensorFlow Lite runtime.");
    while (1);
  }

  // Set up an op resolver
  static tflite::AllOpsResolver resolver;

  // Allocate memory from the tensor_arena for the model's tensors
  static uint8_t tensor_arena_data[kTensorArenaSize];
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1);
  }

  // Point input and output to the respective model inputs/outputs
  input = interpreter->input(0);
  output = interpreter->output(0);

  Serial.println("Setup complete.");
}

void loop() {
  // Read color sensor values
  uint16_t clear, red, green, blue;
  tcs.getRawData(&red, &green, &blue, &clear);

  // Normalize RGB values to [0.0, 1.0] range (assuming 12-bit color depth)
  float r = static_cast<float>(red) / 4095.0f;
  float g = static_cast<float>(green) / 4095.0f;
  float b = static_cast<float>(blue) / 4095.0f;

  // Assign normalized values to input tensor
  TfLiteFloatTensor* input_tensor = interpreter->input(0)->tensor<float>();
  input_tensor->data[0] = r;
  input_tensor->data[1] = g;
  input_tensor->data[2] = b;

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    Serial.println("Failed to invoke the model!");
    return;
  }

  // Process output: Retrieve the result and map it to class names
  const int* output_data = output->data.int32;

  String classNames[] = {"Apple", "Banana", "Orange"};
  int predicted_class_index = *output_data; // Assuming single integer output for class index

  if (predicted_class_index >= 0 && predicted_class_index < 3) {
    Serial.print("Predicted Class: ");
    Serial.println(classNames[predicted_class_index]);
  } else {
    Serial.println("Unknown class");
  }

  delay(1000); // Delay before the next reading
}
