#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/kernels/micro_ops.h>
#include <tensorflow/lite/version.h>
#include "model.h"

#include <ArduinoBLE.h>
#include <Adafruit_NeoPixel.h>
#include <ArduinoJson.h>

// Error reporter for logging
tflite::ErrorReporter* error_reporter = nullptr;

// Tensor arena size defined in the application specification
constexpr int kTensorArenaSize = 2048;
uint8_t tensor_arena[kTensorArenaSize];

void setup() {
  // Initialize Serial communication
  Serial.begin(9600);

  // Set up BLE, NeoPixel, or other peripherals if needed
  // Example for initializing NeoPixels (modify as necessary)
  // Adafruit_NeoPixel strip = Adafruit_NeoPixel(NUMPIXELS, PIN, NEO_GRB + NEO_KHZ800);
  // strip.begin();
  // strip.show();

  // Initialize BLE if used in the application

  // Phase 1: Initialization
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load model into memory
  constexpr int kModelSize = model_data_size / sizeof(uint8_t);
  const uint8_t* model_ptr = model_data;
  tflite::Model* model = tflite::GetModel(model_ptr);

  if (model->version() != TFLITE_SCHEMA_VERSION) {
    TF_LITE_REPORT_ERROR(error_reporter, "Model schema version does not match TensorFlow Lite runtime.");
    return;
  }

  // Set up an op resolver
  static tflite::AllOpsResolver resolver;

  // Configure the interpreter to use the model and the tensor arena
  static tflite::MicroInterpreter static_interpreter(
      model, resolver, tensor_arena, kTensorArenaSize, error_reporter);
  tflite::MicroInterpreter* interpreter = &static_interpreter;

  // Allocate memory from the tensor_arena for the model's tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed");
    return;
  }

  // Retrieve pointers to the input and output tensors
  TfLiteTensor* input_tensor = interpreter->input(0);
