  } else if (predicted_class_index == 1) {
    strip.setPixelColor(0, strip.Color(255, 255, 0)); // Yellow for Banana
  } else {
    strip.setPixelColor(0, strip.Color(0, 128, 0)); // Green for Orange
  }

  strip.show();

  delay(1000); // Wait before the next inference
}
