void setup() {
  // Begin serial communication at 9600 baud rate
  Serial.begin(9600);

  // Allocate tensors and initialize the interpreter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  const TfLiteStatus allocate_status =
      TfLiteInterpreterCreate(model, tensor_arena_size, tensor_arena,
                              resolver.Get(), error_reporter, &interpreter);

  if (allocate_status != kTfLiteOk) {
    Serial.println("Failed to initialize the TensorFlow Lite interpreter.");
    while (1); // Halt execution
  }

  // Allocate memory for tensors.
  TfLiteInterpreterAllocateTensors(interpreter);

  // Get pointers to model's input and output tensors
  TfLiteTensor* input = interpreter->input(0);
  TfLiteTensor* output = interpreter->output(0);

  // Ensure the input tensor has the correct data type (e.g., float for RGB values)
  if (input->type != kTfLiteFloat32) {
    Serial.println("Input tensor is not of expected float type.");
