tflite::ErrorReporter* error_reporter = nullptr;

void setup() {
    // Initialize serial communication at 9600 baud rate.
    Serial.begin(9600);

    // Set up the error reporter
    static tflite::MicroErrorReporter micro_error_reporter;
    error_reporter = &micro_error_reporter;

    // Load model from the path and check version compatibility.
    const tflite::Model* model = tflite::GetModel(g_model);
    if (model->version() != TFLITE_SCHEMA_VERSION) {
        Serial.println("Model schema version does not match TensorFlow Lite runtime.");
        return;
    }

    // Instantiate the interpreter with all necessary components.
    static tflite::MicroInterpreter static_interpreter(
        model, tflite::ops::micro::AllOpsResolver(), tensor_arena,
        kTensorArenaSize, error_reporter);
    tflite::MicroInterpreter* interpreter = &static_interpreter;

    // Allocate memory for tensors from the tensor arena.
    TfLiteStatus allocate_status = interpreter->AllocateTensors();
    if (allocate_status != kTfLiteOk) {
        Serial.println("Failed to allocate tensors!");
        return;
    }

    // Obtain pointers to input and output tensors.
    TfLiteTensor* input = interpreter->input(0);
    TfLiteTensor* output = interpreter->output(0);

    while (true) {
        // Simulate sensor data acquisition with sample RGB values.
        float simulatedSensorData[3] = {0.5, 0.25, 0.2}; // Example RGB values

        // Copy the data to the input tensor buffer.
        for (size_t i = 0; i < input->dims->data[1]; ++i) {
            input->data.f[i] = simulatedSensorData[i];
        }

        // Run inference with the interpreter.
        TfLiteStatus invoke_status = interpreter->Invoke();
        if (invoke_status != kTfLiteOk) {
            Serial.println("Failed to invoke!");
            continue;
        }

        // Determine the class with the highest score from the output tensor.
        int predicted_class = 0;
        float max_score = -1.0;
        for (size_t i = 0; i < output->dims->data[1]; ++i) {
            if (output->data.uint8[i] > max_score) {
                max_score = output->data.uint8[i];
                predicted_class = static_cast<int>(i);
            }
        }

        // Output the class label using Unicode emojis.
        const char* emoji_map[] = {"🍎", "🍌", "🍊"};
        Serial.print("Classified as: ");
        Serial.println(emoji_map[predicted_class]);

        delay(1000); // Delay to simulate processing time
    }
}

void loop() {
  // Intentionally left empty; setup function contains the main logic.
}
