#include <TensorFlowLite.h>
#include "model.h"
#include "Arduino_LSM9DS1.h"
#include "Adafruit_Sensor.h"

// Define Tensor Arena Size
constexpr int tensor_arena_size = 4096;

// Declare TensorFlow Lite variables
tflite::ErrorReporter* error_reporter;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;
TfLiteTensor* input_tensor = nullptr;

// Color sensor calibration values (example)
float redCalibration = 1.0, greenCalibration = 1.0, blueCalibration = 1.0;

void setup() {
  // Initialize Serial
  Serial.begin(9600);

  // Initialize TensorFlow Lite variables
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Define tensor arena
  uint8_t tensor_arena[tensor_arena_size];

  // Load the model
  model = tflite::GetModel(model_data);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version mismatch!");
    while (1) {}
  }

  // Resolve operators
  static tflite::MicroOpResolver<3> micro_op_resolver;

  // Instantiate the interpreter
  static tflite::MicroInterpreter static_interpreter(
      model, micro_op_resolver, tensor_arena,
      tensor_arena_size, error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory for tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    Serial.println("Tensor allocation failed!");
    while (1) {}
  }

  // Get input tensor details
  input_tensor = interpreter->input(0);

  // Initialize the color sensor
  if (!IMU.begin()) {
    Serial.println("Failed to initialize IMU!");
    while (1) {}
  }
}

void loop() {
  float red, green, blue;

  // Read color sensor data
  sensors_event_t event;
  IMU.colorSensor.getEvent(&event);
  red = event.red / 65536.0 * redCalibration;
  green = event.green / 65536.0 * greenCalibration;
  blue = event.blue / 65536.0 * blueCalibration;

  // Copy data to input tensor
  float* input_ptr = interpreter->input(0)->data.f;
  input_ptr[0] = red;
  input_ptr[1] = green;
  input_ptr[2] = blue;

  // Invoke the interpreter
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    Serial.println("Model inference failed!");
    while (1) {}
  }

  // Process output tensor and classify object
  uint8_t* output_ptr = interpreter->output(0)->data.uint8;
  int class_idx = std::distance(output_ptr, 
                                std::max_element(output_ptr, output_ptr + 3));

  const char* emojis[] = {"🍎", "🍌", "🍊"};

  // Output the classification result
  Serial.print("Object: ");
  Serial.println(emojis[class_idx]);

  delay(1000);  // Delay for readability
}
