```cpp
#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/kernels/micro_ops.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/micro/micro_interpreter.h>
#include <tensorflow/lite/schema/schema_generated.h>

#include "Arduino_LSM9DS1.h"
#include "Adafruit_Sensor.h"

// Include the model file generated by TensorFlow Lite
extern const unsigned char model[];
extern const int model_size;

const int tensor_arena_size = 4096;
uint8_t tensor_arena[tensor_arena_size];

tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Declare pointers for the model and interpreter
const tflite::Model* model_instance;
tflite::MicroInterpreter* interpreter;

void setup() {
  Serial.begin(9600);

  // Initialize the color sensor (In-built LSM9DS1)
  if (!IMU.begin()) {
    Serial.println("Failed to initialize IMU!");
    while (1);
  }

  // Load the model
  model_instance = tflite::GetModel(model);
  if (model_instance->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match TensorFlow Lite runtime.");
    while (1);
  }

  // Set up an OpResolver and allocate memory for the interpreter
  static tflite::AllOpsResolver resolver;
  static tflite::MicroInterpreter static_interpreter(
      model_instance, resolver, tensor_arena, tensor_aura_size, error_reporter);

  interpreter = &static_interpreter;

  // Allocate tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1);
  }

  // Get pointers to the input and output tensors
  TfLiteTensor* input_tensor = interpreter->input(0);
  TfLiteTensor* output_tensor = interpreter->output(0);

  // Check tensor dimensions
  if ((input_tensor->dims->data[0] != 1) || (input_tensor->dims->data[1] != 3)) {
    Serial.println("Input tensor dimensions do not match expected size.");
    while (1);
  }

  if ((output_tensor->dims->data[0] != 1) || (output_tensor->dims->data[1] != 3)) {
    Serial.println("Output tensor dimensions do not match expected size.");
    while (1);
  }
}

void loop() {
  // Read color sensor data
  float red, green, blue;
  if (IMU.colorAvailable()) {
    IMU.readColor(&red, &green, &blue);

    // Normalize the values to be between 0 and 1
    float input_data[3] = {red / 255.0f, green / 255.0f, blue / 255.0f};

    // Copy data to the input tensor
    memcpy(interpreter->input(0)->data.f, input_data, sizeof(input_data));

    // Run inference
    TfLiteStatus invoke_status = interpreter->Invoke();
    if (invoke_status != kTfLiteOk) {
      Serial.println("Failed to invoke!");
      return;
    }

    // Get the classification result
    float* output_ptr = interpreter->output(0)->data.f;
    int max_index = 0;
    for (int i = 1; i < 3; ++i) {
      if (output_ptr[i] > output_ptr[max_index]) {
        max_index++;
      }
    }

    // Map the index to a class name
    const char* classes[] = {"Apple", "Banana", "Orange"};
    Serial.print("Detected: ");
    Serial.println(classes[max_index]);

    delay(1000);
  } else {
    Serial.println("Color data not available.");
    delay(500);
  }
}
