  if ((output_tensor->dims->data[0] != 1) || (output_tensor->dims->data[1] != 3)) {
    Serial.println("Output tensor dimensions do not match expected size.");
    while (1);
  }
}

void loop() {
  // Read color sensor data
  float red, green, blue;

  if (IMU.accelerationAvailable()) { // Ensure the IMU is available as a proxy for color sensing capability
