      red = map(x, -32768, 32767, 0, 255);
      green = map(y, -32768, 32767, 0, 255);
      blue = map(z, -32768, 32767, 0, 255);
    }

    // Normalize the values to be between 0 and 1
    float input_data[3] = {red / 255.0f, green / 255.0f, blue / 255.0f};

    // Copy data to the input tensor
    memcpy(interpreter->input(0)->data.f, input_data, sizeof(input_data));

    // Run inference
    TfLiteStatus invoke_status = interpreter->Invoke();
    if (invoke_status != kTfLiteOk) {
      Serial.println("Failed to invoke!");
      return;
    }

    // Get the classification result
    float* output_ptr = interpreter->output(0)->data.f;
    int max_index = 0;
    for (int i = 1; i < 3; ++i) {
      if (output_ptr[i] > output_ptr[max_index]) {
        max_index = i;
      }
