    // Get the classification result
    float* output_ptr = interpreter->output(0)->data.f;
    int max_index = 0;
    for (int i = 1; i < 3; ++i) {
        if (output_ptr[i] > output_ptr[max_index]) {
            max_index = i;
        }
    }

