#include "TensorFlowLite.h"
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/kernels/micro_ops.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "tensorflow/lite/version.h"
#include "Arduino_LSM9DS1.h"

#include "model.h"  // Include the path to the model file

constexpr int kTensorArenaSize = 2048;
static uint8_t tensor_arena[kTensorArenaSize];

tflite::ErrorReporter* error_reporter = nullptr;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;

TfLiteTensor* input = nullptr;
TfLiteTensor* output = nullptr;

void setup() {
  Serial.begin(9600);

  // Initialize the Error Reporter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load model and allocate tensors.
  model = tflite::GetModel(model_tflite);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match TensorFlow Lite runtime.");
    return;
  }

  static tflite::AllOpsResolver resolver;

  // Build an interpreter to run the model with.
  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena,
                                             kTensorArenaSize, error_reporter);
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    return;
  }

  // Get pointers to the model's input and output tensors.
  input = interpreter->input(0);
  output = interpreter->output(0);

  // Initialize sensors
  if (!IMU.begin()) {
    Serial.println("Failed to initialize IMU!");
  }
}

void loop() {
  float red, green, blue;

  // Simulate reading from the onboard RGB color sensor
  if (IMU.colorAvailable()) {
    IMU.readColor(red, green, blue);

    // Normalize input values to match model's expected range [0.5, 0.636], etc.
    red = mapf(red, 0, 1, 0.5, 0.636); 
    green = mapf(green, 0, 1, 0.182, 0.292);
    blue = mapf(blue, 0, 1, 0.167, 0.25);

    // Copy input data to the tensor
    input->data.f[0] = red;
    input->data.f[1] = green;
    input->data.f[2] = blue;

    // Run inference
    if (interpreter->Invoke() == kTfLiteOk) {
      int index = output->data.uint8[0];
      String classEmoji = "";

      switch (index) {
        case 0:
          classEmoji = "🍎";
          break;
        case 1:
          classEmoji = "🍌";
          break;
        case 2:
          classEmoji = "🍊";
          break;
        default:
          Serial.println("Unknown classification.");
      }

      Serial.print("Classified as: ");
      Serial.println(classEmoji);
    } else {
      Serial.println("Failed to invoke interpreter!");
    }
  }

  delay(1000); // Adjust delay based on sensor reading rate and application needs
}

float mapf(float x, float in_min, float in_max, float out_min, float out_max) {
  return (x - in_min) * (out_max - out_min) / (in_max - in_min) + out_min;
}
