#include <Arduino_LSM9DS1.h>

// Include TensorFlow Lite for Microcontrollers library
#include "TensorFlowLite.h"
#include "tensorflow/lite/micro/kernels/micro_ops.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "tensorflow/lite/version.h"

// IMPORTANT: Always include the model file after all other headers.
#include "model.h"

namespace {
  // Create a namespace for global variables and function implementations.

  // Define the tensor arena size. It must be large enough to hold
  // all of the tensors used by the root graph, plus some space for
  // intermediate arrays allocated during inference (e.g., output
  // blobs, activation scratch buffers, etc).
  constexpr int kTensorArenaSize = 2048;

  // Create a buffer to hold inference-related data.
  uint8_t tensor_arena[kTensorArenaSize];

  // Instantiate an error reporter. This can be used to report errors,
  // log them and optionally halt the execution.
  tflite::MicroErrorReporter micro_error_reporter;
  const tflite::ErrorReporter* error_reporter = &micro_error_reporter;

  // Create an interpreter to run the model with.
  static tflite::MicroInterpreter* interpreter;

  TfLiteTensor* input;
  TfLiteTensor* output;

  void InitializeTfLite() {
    // Instantiate an OpResolver. This is used to resolve the operation
    // codes included in the flatbuffer to concrete C++ classes that can
    // be invoked.
    static tflite::MicroOpResolver<3> resolver(
        tflite::BuiltinOperator_DEPTHWISE_CONV_2D,
        tflite::BuiltinOperator_MAX_POOL_2D,
        tflite::BuiltinOperator_CONV_2D);

    const char* model_data = GetModelData(); // Load the model here.
    // Build an interpreter to run the model with. This creates an
    // object with a lot of heap-allocated memory for running inference.
    static tflite::MicroInterpreter static_interpreter(
        model, resolver, tensor_arena, kTensorArenaSize,
        error_reporter);
    interpreter = &static_interpreter;

    // Allocate memory from the tensor_arena for the model's tensors.
    TfLiteStatus allocate_status = interpreter->AllocateTensors();
    if (allocate_status != kTfLiteOk) {
      TF_LITE_REPORT_ERROR(error_reporter, "Failed to allocate tensors\n");
      return;
    }

    input = interpreter->input(0);
    output = interpreter->output(0);

    // Initialize all peripherals here.
  }
}

void setup() {
  Serial.begin(9600);

  if (!IMU.begin()) {
    TF_LITE_REPORT_ERROR(error_reporter, "Failed to initialize IMU!\n");
    while (1) {}
  }

  InitializeTfLite();
}

void loop() {
  float red, green, blue;

  // Read the RGB color sensor.
  if (IMU.colorAvailable()) {
    IMU.readColor(red, green, blue);

    input->data.f[0] = red;
    input->data.f[1] = green;
    input->data.f[2] = blue;

    TfLiteStatus invoke_status = interpreter->Invoke();
    if (invoke_status != kTfLiteOk) {
      TF_LITE_REPORT_ERROR(error_reporter, "Failed to invoke!\n");
      return;
    }

    uint8_t predicted_class = output->data.uint8[kOutputIndex];

    switch (predicted_class) {
      case 0:
        Serial.println("🍎"); // Apple
        break;
      case 1:
        Serial.println("🍌"); // Banana
        break;
      case 2:
        Serial.println("🍊"); // Orange
        break;
      default:
        TF_LITE_REPORT_ERROR(error_reporter, "Unknown class\n");
    }
  }

  delay(1000);
}
