#include <tensorflow/lite/version.h>
#include "model.h"
#include <Wire.h>
#include <Adafruit_APDS9960.h>

// Error reporter for TFLM
static tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Tensor Arena: allocate a suitable size according to the model requirements and available memory
constexpr int tensor_arena_size = 2048;
uint8_t tensor_arena[tensor_arena_size];

// Model pointer and interpreter
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;

// Input and output tensors pointers
TfLiteTensor* input_tensor = nullptr;
TfLiteTensor* output_tensors[3]; // Assuming there are 3 output tensors

Adafruit_APDS9960 apds; // Color sensor instance

void setup() {
    Serial.begin(9600);

    if (!apds.begin()) {
        Serial.println("Failed to initialize APDS-9960");
        while (1); // Halt on failure
    }

    model = tflite::GetModel(model_data);
    if (model->version() != TFLITE_SCHEMA_VERSION) {
        Serial.println("Model schema version does not match TensorFlow Lite runtime.");
        return;
    }

    static tflite::AllOpsResolver resolver;

    // Create an interpreter to run the model
    tflite::MicroInterpreter static_interpreter(
        model, resolver, tensor_arena, tensor_arena_size, error_reporter);
    interpreter = &static_interpreter;

    // Allocate memory from the tensor arena for the model's tensors
    TfLiteStatus allocate_status = interpreter->AllocateTensors();
    if (allocate_status != kTfLiteOk) {
        Serial.println("Failed to allocate tensors!");
        return;
    }

    // Get pointers to the input and output tensors
    input_tensor = interpreter->input(0);
    for (int i = 0; i < interpreter->outputs()->size(); ++i) {
        output_tensors[i] = interpreter->output(i);
    }
}

void loop() {
    uint16_t r, g, b;

    // Check if color data is available
    if (!apds.colorAvailable()) {
        Serial.println("No color data available");
        return;
    }

    // Read color values from the sensor
    if (!apds.readColorData(&r, &g, &b)) {
