  Serial.begin(9600);
  while (!Serial); // Wait for serial connection

  // Initialize error reporter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load the model from memory
  constexpr uint8_t kModel[] = {
    // Add your model data here (ensure it is correctly formatted)
  };

  model = tflite::GetModel(kModel);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version mismatch.");
    return;
  }

  // Set up the OpResolver
  static tflite::AllOpsResolver resolver;

  // Allocate memory from the tensor_arena for the model's tensors
  static uint8_t tensor_arena[TENSOR_ARENA_SIZE];
  tflite::MicroInterpreter interpreter(
      model, resolver, tensor_arena, TENSOR_ARENA_SIZE, error_reporter);

  // Allocate memory for tensors and get pointers to input and output tensors
  interpreter.AllocateTensors();
  input_tensor = interpreter.input(0);
  output_tensor = interpreter.output(0);

  // Initialize the APDS9960 sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS-9960");
    while (1); // Halt on failure
  }

  apds.enableColorSensor(true);
}

void loop() {
  uint16_t red, green, blue;

  // Read RGB values from the sensor
  if (!apds.readAmbientLightGestureProximity()) {
    Serial.println("Failed to read color data");
    return;
  }

  if (!apds.getColorData(&red, &green, &blue)) {
    Serial.println("Failed to get color data");
    return;
  }

  // Normalize the RGB values
  float red_norm = static_cast<float>(red) / 1023.0f;
  float green_norm = static_cast<float>(green) / 1023.0f;
  float blue_norm = static_cast<float>(blue) / 1023.0f;

  // Prepare input tensor data
  const float* input_data = input_tensor->data.f;
  input_data[0] = red_norm;
  input_data[1] = green_norm;
  input_data[2] = blue_norm;

  // Run inference
  if (interpreter.Invoke() != kTfLiteOk) {
    Serial.println("Failed to invoke the interpreter");
    return;
