  // Build an interpreter to run the model with.
  interpreter = new tflite::MicroInterpreter(
      tflite_model, micro_op_resolver, tensor_arena, kTensorArenaSize,
      settings);

  TfLiteStatus allocate_status =
      interpreter->AllocateTensors(); // Allocate memory from the tensor_arena.
  if (allocate_status != kTfLiteOk) {
    error("AllocateTensors() failed");
    while (1) delay(10);
  }

  // Obtain pointers to the model's input and output tensors.
  input = interpreter->input(0)->data.f;
  output = interpreter->output(0)->data.uint8;

  DEBUG_PRINT(Serial, "TensorArenaSize: ");
  Serial.println(kTensorArenaSize);

  // Print model summary
  const tflite::Model* tflite_model_loaded =
      reinterpret_cast<const tflite::Model*>(interpreter->model());
  DEBUG_PRINT(Serial, "\n\n");
  DEBUG_PRINT(Serial, "Model information:\n");
  DEBUG_PRINT(Serial, "  Model name: %s\n", tflite_model_loaded->model_name);
  DEBUG_PRINT(
      Serial,
      "  Microcontroller spec: %s\n",
      TfLiteMicroControllerTypeGetName(tflite_model_loaded->microcontroller_spec));
  DEBUG_PRINT(
      Serial,
      "  Author: %s\n\n",
      tflite_model_loaded->author);

  const int num_subgraphs = tflite_model_loaded->subgraph_count;
  for (int s = 0; s < num_subgraphs; ++s) {
    const auto* subgraph = tflite_model_loaded->subgraphs[s];
    const int num_inputs = subgraph->inputs->size;
    DEBUG_PRINT(
        Serial,
        "Subgraph %d:\n",
        s);
    for (int i = 0; i < num_inputs; ++i) {
      const auto input_tensor_index = (*subgraph->inputs)[i];
      const TfLiteTensor* t =
          subgraph->tensors + input_tensor_index;
      DEBUG_PRINT(Serial, "  Input %d: ", i);
      PrintTensorShapeAndType(tflite::GetTensorName(subgraph, input_tensor_index),
                              t, Serial);
    }
    const int num_outputs = subgraph->outputs->size;
    for (int o = 0; o < num_outputs; ++o) {
      const auto output_tensor_index = (*subgraph->outputs)[o];
      const TfLiteTensor* t =
          subgraph->tensors + output_tensor_index;
      DEBUG_PRINT(Serial, "  Output %d: ", o);
      PrintTensorShapeAndType(tflite::GetTensorName(subgraph, output_tensor_index),
                              t, Serial);
    }
    const int num_nodes = subgraph->node_count;
    for (int n = 0; n < num_nodes; ++n) {
      const auto* node = subgraph->nodes + n;

      TfLiteRegistration registration;
      if (GetNodeRegistration(node, &registration)) {
        DEBUG_PRINT(
            Serial,
            "  Node %d: type=%s\n",
            n,
            TfLiteRegistrationGetName(registration));
        for (int i = 0; i < node->inputs->size; ++i) {
          const auto input_tensor_index = (*node->inputs)[i];
          DEBUG_PRINT(Serial, "    Input %d: ", i);
          PrintTensorShapeAndType(tflite::GetTensorName(subgraph,
                                                        input_tensor_index),
                                  subgraph->tensors + input_tensor_index,
                                  Serial);
        }
      }
    }
  }

  DEBUG_PRINT(Serial, "\n");
}

void loop() {
  uint16_t r, g, b;

  // Read the color values
  if (!apds.readColor(r, g, b)) {
    error("Failed to read RGB data.");
    delay(1000);
    return;
  }

  DEBUG_PRINT(Serial, "Read RGB: ");
  Serial.print("R: "); Serial.print((float)r / 256.0); Serial.print(" G: ");
  Serial.print((float)g / 256.0); Serial.print(" B: "); Serial.println(
      (float)b / 256.0);

  // Normalize the input data to [0,1] range
  input[0] = (float)r / 255;
  input[1] = (float)g / 255;
  input[2] = (float)b / 255;

  DEBUG_PRINT(Serial, "Running inference\n");
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    error("Invoke failed!");
    while (1) delay(10);
  }

  // Get the highest index in the output tensor
  int max_index = -1;
  float max_value = 0.0;
  for (int i = 0; i < 3; ++i) {
    if (output[i] > max_value) {
      max_index = i;
      max_value = output[i];
    }
  }

  DEBUG_PRINT(Serial, "Classification: %s", kClassLabels + max_index * 8);
  Serial.print(" - Class: "); Serial.println(kClassLabels + max_index * 8);

  // Output the classification result as an emoji
  const char* emoji = "\U0001F34E"; // Apple Emoji
  if (max_index == 1) {
    emoji = "\U0001F34C"; // Banana Emoji
  } else if (max_index == 2) {
    emoji = "\U0001F34A"; // Orange Emoji
  }

  DEBUG_PRINT(Serial, "Result: %s\n", emoji);
  Serial.print(emoji);

  delay(1000); // Wait for a second before the next reading
}
