```cpp
#include <TensorFlowLite.h>
#include <Wire.h>
#include "Adafruit_APDS9960.h"
#include "model.h"

// Global variables for TensorFlow Lite Micro
tflite::ErrorReporter* error_reporter = nullptr;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;
TfLiteTensor* input = nullptr;

// Tensor arena size must be large enough to fit the tensor allocations.
constexpr int kTensorArenaSize = 1024;
uint8_t tensor_arena[kTensorArenaSize];

Adafruit_APDS9960 apds;

void setup() {
  // Initialize Serial for debugging
  Serial.begin(9600);

  // Setup error reporter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load model from model.h file
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match TensorFlow Lite runtime.");
    return;
  }

  // Select operations to be used by the interpreter.
  static tflite::ops::micro::AllOpsResolver resolver;

  // Create an area of memory to use for input, output, and intermediate arrays.
  static uint8_t tensor_arena[kTensorArenaSize];

  // Build an interpreter to run the model with
  static tflite::MicroInterpreter static_interpreter(
      model, resolver, tensor_arena, kTensorArenaSize, error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory from the tensor_arena for the model's tensors.
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    Serial.println("Model could not be allocated");
    return;
  }

  // Get input tensor details
  input = interpreter->input(0);

  // Initialize and configure the APDS9960 color sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS-9960");
    while (1);
  }

  // Enable proximity detection (if needed)
  apds.enableProximitySensor(false);

  // Start running the color sensor
  if (!apds.enableColorSensor(true)) {
    Serial.println("Could not enable color sensor!");
    while (1);
  }

  Serial.println("Setup complete");
}

void loop() {
  uint16_t r, g, b;

  // Read RGB values from APDS9960
  if (apds.readColorData(&r, &g, &b)) {

    // Normalize color values to the range [0,1] and scale by 255 for TensorFlow input requirements
    float red = static_cast<float>(r) / 255.0;
    float green = static_cast<float>(g) / 255.0;
    float blue = static_cast<float>(b) / 255.0;

    // Copy data to the model's input tensor
    memcpy(input->data.f, &red, sizeof(float));
    memcpy((input->data.f + 1), &green, sizeof(float));
    memcpy((input->data.f + 2), &blue, sizeof(float));

    // Run inference
    TfLiteStatus invoke_status = interpreter->Invoke();
    if (invoke_status != kTfLiteOk) {
      Serial.println("Failed to invoke the model");
      return;
    }

    // Get output from the model
    const TfLiteTensor* output_tensor = interpreter->output(0);

    // Determine classification based on max value index
    float max_val = -1.0;
    int class_index = 0;
    for (int i = 0; i < 3; ++i) {
      if (output_tensor->data.uint8[i] > max_val) {
        max_val = output_tensor->data.uint8[i];
        class_index = i;
      }
    }

    // Map the classification index to a fruit name
    const char* classes[] = {"Apple", "Banana", "Orange"};
    Serial.print("Detected: ");
    Serial.println(classes[class_index]);
  } else {
    Serial.println("Failed to read color data");
  }

  delay(1000);
}
