    if (input_tensor->type == kTfLiteFloat32) {
        float* input_data = interpreter->typed_input_tensor<float>(0);
        for (size_t i = 0; i < kModelInputSize; ++i) {
            input_data[i] = 0.0f;
        }
    }

    // Setup other relevant parts
}

