```cpp
#include "TensorFlowLite.h"
#include "model.h"

// Define Tensor Arena size
constexpr int kTensorArenaSize = 1024;

// Declare variables for TensorFlow Lite Micro
tflite::ErrorReporter* error_reporter;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;
TfLiteTensor* input = nullptr;

// Array to hold the tensor arena buffer
byte tensor_arena[kTensorArenaSize];

void setup() {
  // Initialize serial communication for output
  Serial.begin(9600);

  // Set up TensorFlow Lite components

  // Initialize error reporter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load model into memory
  model = tflite::GetModel(model_data);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match TensorFlow Lite runtime.");
    while (1) {}
  }

  // Resolve operators
  static tflite::ops::micro::AllOpsResolver resolver;

  // Set up tensor arena and allocate memory for tensors
  static uint8_t tensor_arena_offset = 0;
  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena,
                                             kTensorArenaSize, &tensor_arena_offset, error_reporter);

  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1) {}
  }

  // Get pointers to input and output tensors
  input = interpreter->input(0);

  // Sensor setup can be placed here if needed, for now we simulate sensor input
}

void loop() {
  // Simulate RGB sensor data
  float simulatedData[3] = {0.522, 0.261, 0.217};

  // Copy simulated data to input tensor
  for (size_t i = 0; i < input->bytes / sizeof(float); ++i) {
    ((float*)input->data)[i] = simulatedData[i];
  }

  // Run inference
  if (interpreter->Invoke() == kTfLiteOk) {
    // Get pointer to the output tensor
    TfLiteTensor* output = interpreter->output(0);

    // Process output: get predicted class
    int predicted_class_index = -1;
    float max_value = -1.0;

    for (size_t i = 0; i < output->bytes / sizeof(uint8_t); ++i) {
      if ((float)((uint8_t*)output->data)[i] > max_value) {
        max_value = (float)((uint8_t*)output->data)[i];
        predicted_class_index = i;
      }
    }

    // Define class labels
    const char* classes[] = {"Apple", "Banana", "Orange"};

    // Output the result using Unicode emojis via Serial
    if (predicted_class_index >= 0 && predicted_class_index < 3) {
      switch (predicted_class_index) {
        case 0:
          Serial.println("🍎"); // Apple emoji
          break;
        case 1:
          Serial.println("🍌"); // Banana emoji
          break;
        case 2:
          Serial.println("🍊"); // Orange emoji
          break;
      }
    }
  } else {
    Serial.println("Failed to invoke the interpreter.");
  }

  delay(1000); // Run inference every second
}
