int main() {
  // Initialize serial communication at 9600 baud rate for debugging purposes.
  Serial.begin(9600);
  while (!Serial);

  // Set up the error reporter.
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Map the model into a usable data structure. This doesn't involve any copying
  // or parsing, it's a very lightweight operation.
  const tflite::Model* model = tflite::GetModel(g_model);

  if (model->version() != TFLITE_SCHEMA_VERSION) {
    TF_LITE_REPORT_ERROR(error_reporter, "Model schema version does not match TensorFlow Lite runtime.");
    return -1;
  }

  // Pull in only the operation implementations we need.
  // This relies on a complete list of all the ops needed by this graph.
  static tflite::AllOpsResolver resolver;

  // Build an interpreter to run the model with.
  static tflite::MicroInterpreter static_interpreter(
      model, resolver, tensor_arena, kTensorArenaSize, error_reporter);
  tflite::MicroInterpreter* interpreter = &static_interpreter;

  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter,
                         "AllocateTensors() failed on model: %s\n%s\n",
                         model->name, GetErrorMessage(allocate_status));
    return -1;
  }

  // Retrieve pointers to the input and output tensors.
  TfLiteTensor* input = interpreter->input(0);
  TfLiteTensor* output = interpreter->output(0);

  while (true) {
    if (!IMU.begin()) {
      Serial.println("Failed to initialize IMU!");
      delay(1000);
      continue;
    }

    // Check if the IMU has a new color reading available.
    float red, green, blue;
    if (IMU.colorAvailable()) {
      IMU.readColor(red, green, blue);

      // Copy input data into the tensor.
      input->data.f[0] = red;
      input->data.f[1] = green;
      input->data.f[2] = blue;

      // Run inference.
      TfLiteStatus invoke_status = interpreter->Invoke();
      if (invoke_status != kTfLiteOk) {
        TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed on model: %s\n%s\n",
                             model->name, GetErrorMessage(invoke_status));
        continue;
      }

      // Process the output.
      uint8_t max_index = 0;
      float max_value = 0.0f;

      for (int i = 0; i < output->dims->data[1]; ++i) {
        if (output->data.uint8[i] > max_value) {
          max_value = output->data.uint8[i];
          max_index = i;
        }
      }

      // Map the index to a class label.
      const char* labels[] = {"Apple", "Banana", "Orange"};
      Serial.print("Detected object: ");
      Serial.println(labels[max_index]);

      // Output result using Unicode emojis via serial.
      if (max_index == 0) {
        Serial.write(0x1F34E);  // Apple emoji
      } else if (max_index == 1) {
        Serial.write(0x1F34C);  // Banana emoji
      } else if (max_index == 2) {
        Serial.write(0x1F34A);  // Orange emoji
      }
    }

    delay(1000);
  }

  return 0;
}
