uint8_t tensor_arena[kTensorArenaSize];      // Memory space for tensors

// Function to setup the model and interpreter
void SetupModel() {
  static tflite::Model* model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match TensorFlow Lite runtime.");
    while (1) {}
  }

  // Resolve the operators
  static tflite::ops::micro::AllOpsResolver resolver;

  // Build an interpreter to run the model with
  static const int tensor_arena_size = kTensorArenaSize;
