#include "tensorflow/lite/schema/schema_generated.h"

#include <Arduino_LSM9DS1.h>  // For sensor input if needed
#include <ArduinoBLE.h>        // For BLE functionality

// Include your model header
#include "model.h" 

constexpr int tensor_arena_size = 1024;

namespace {
  tflite::ErrorReporter* error_reporter = nullptr;
  const tflite::Model* model = nullptr;
  tflite::MicroInterpreter* interpreter = nullptr;
  TfLiteTensor* input = nullptr;
  TfLiteTensor* output = nullptr;
}

void setup() {
  // Initialize serial communication
  Serial.begin(9600);

  // Setup sensors or other hardware components
  if (!IMU.begin()) {
    Serial.println("Failed to initialize IMU!");
    while (1);
  }

  // Allocate memory for the tensor arena
  uint8_t tensor_arena[tensor_arena_size];

  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load model
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version mismatch!");
    while (1);
  }

  // Use AllOpsResolver to resolve all operators needed by the model
  static tflite::AllOpsResolver resolver;

  // Create an interpreter to run the model
  static tflite::MicroInterpreter static_interpreter(
      model, resolver, tensor_arena, tensor_arena_size, error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory from the tensor arena for the model's tensors
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1);
  }

  // Obtain pointers to the input and output tensors
  input = interpreter->input(0);
  output = interpreter->output(0);

  // Verify that we're getting the expected tensor dimensions
  if ((input->dims->size != 2) || (input->dims->data[0] != 1) ||
      (input->dims->data[1] != 3)) {
    Serial.println("Unexpected input tensor shape!");
    while (1);
  }
}

void loop() {
  // Acquire sensor data
  float red = random(50, 64); / 100.0;
  float green = random(18, 29) / 100.0;
