// Define the tensor arena size
constexpr int kTensorArenaSize = 1024;

// Declare TensorFlow Lite variables
tflite::ErrorReporter* error_reporter;
const tflite::Model* model = nullptr;
std::unique_ptr<tflite::MicroInterpreter> interpreter;
TfLiteTensor* input = nullptr;
TfLiteTensor* output = nullptr;

// Declare RGB sensor object
Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

void setup() {
  // Initialize serial communication for debugging and output
  Serial.begin(9600);

  // Initialize the error reporter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Allocate tensor arena buffer
  uint8_t tensor_arena[kTensorArenaSize];

  // Load model and check validity
  model = tflite::GetModel(model_data);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version mismatch!");
    return;
  }

  // Use AllOpsResolver to register all the necessary operators
  static tflite::AllOpsResolver resolver;

  // Create interpreter with tensor arena and error reporter
  interpreter = std::make_unique<tflite::MicroInterpreter>(model, resolver, tensor_arena,
                                                           kTensorArenaSize, error_reporter);

  // Allocate memory for tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    return;
  }

  // Retrieve input and output pointers
  input = interpreter->input(0);
  output = interpreter->output(0);

  // Initialize TCS34725 color sensor
  if (!tcs.begin()) {
    Serial.println("TCS34725 not found. Check wiring!");
    while (1); // Halt on error
  }
}

void loop() {
  uint16_t clear, red, green, blue;

  // Read RGB values from the TCS34725 sensor
  tcs.getRawData(&red, &green, &blue, &clear);

  // Normalize and convert the raw values to float32 for input tensor
  float red_norm = static_cast<float>(red) / clear;
  float green_norm = static_cast<float>(green) / clear;
  float blue_norm = static_cast<float>(blue) / clear;

  input->data.f[0] = red_norm;
  input->data.f[1] = green_norm;
  input->data.f[2] = blue_norm;

  // Invoke the interpreter to run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    Serial.println("Failed to invoke!");
    return;
  }

  // Process output and map it to object classes
  int max_index = 0;
  float max_value = -1.0f;
  for (int i = 0; i < 3; ++i) {
    if (output->data.uint8[i] > max_value) {
      max_value = static_cast<float>(output->data.uint8[i]);
      max_index = i;
    }
  }

  // Map to corresponding emoji
  const char* emojis[] = { "🍎", "🍌", "🍊" };
  Serial.print("Detected object: ");
  Serial.println(emojis[max_index]);

  delay(1000); // Wait for a second before the next reading
}
