    extern const unsigned char g_model[];

    // Static memory buffer for TFLite runtime.
    uint8_t tensor_arena[kTensorArenaSize];
} 

// Declare pointers for the model and interpreter
tflite::MicroErrorReporter micro_error_reporter;
const tflite::Model* model = tflite::GetModel(g_model);
static tflite::MicroInterpreter* interpreter;

void setup() {
    // Initialize serial communication
    Serial.begin(9600);

    // Setup the RGB color sensor
    Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);
    if (!tcs.begin()) {
        Serial.println("Failed to initialize the color sensor!");
        while (1); // Halt execution
    }

    // Initialize the error reporter and model validation
    tflite::MicroErrorReporter micro_error_reporter;
    static tflite::MicroInterpreter static_interpreter(
        model, tflite::ops::micro::AllOpsResolver(), tensor_arena, kTensorArenaSize, &micro_error_reporter);

    // Allocate memory from the tensor arena for the interpreter's tensors
    TfLiteStatus allocate_status = static_interpreter.AllocateTensors();
    if (allocate_status != kTfLiteOk) {
        Serial.println("Failed to allocate tensors!");
        while (1); // Halt execution
    }

    // Save the pointer to the static interpreter instance
    interpreter = &static_interpreter;

    // Retrieve pointers to input and output tensors
    TfLiteTensor* model_input = interpreter->input(0);
}

void loop() {
    // Read sensor data
    uint16_t r, g, b, c;
    Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

    if (tcs.getRawData(&r, &g, &b, &c)) {
        // Normalize the data
        float red_norm = static_cast<float>(r) / c;
        float green_norm = static_cast<float>(g) / c;
        float blue_norm = static_cast<float>(b) / c;

        // Copy sensor data to the input tensor
        TfLiteTensor* model_input = interpreter->input(0);
        if (model_input->type == kTfLiteFloat32) {
            float* input_data = reinterpret_cast<float*>(model_input->data.f);
            input_data[0] = red_norm;
            input_data[1] = green_norm;
            input_data[2] = blue_norm;
        } else {
            Serial.println("Model input type mismatch!");
            return;
        }

        // Run inference
        TfLiteStatus invoke_status = interpreter->Invoke();
        if (invoke_status != kTfLiteOk) {
            Serial.println("Failed to invoke the model!");
            while (1); // Halt execution
        }

        // Retrieve and process output tensor data
        TfLiteTensor* output_tensor = interpreter->output(0);
        if (output_tensor->type == kTfLiteUInt8) {
            uint8_t* output_data = reinterpret_cast<uint8_t*>(output_tensor->data.uint8);
            const char* classes[] = {"Apple", "Banana", "Orange"};

            // Find the index of the maximum output value
            int max_index = 0;
            for (int i = 1; i < 3; ++i) {
                if (output_data[i] > output_data[max_index]) {
                    max_index = i;
                }
            }

            // Print the classification result
            Serial.print("Classified as: ");
            Serial.println(classes[max_index]);
        } else {
            Serial.println("Model output type mismatch!");
        }
    } else {
        Serial.println("Failed to read sensor data.");
    }

    delay(1000);  // Wait before the next reading
}
