#include "Arduino_LoRaWAN.h"
#include "SPI.h"
#include "model.h"

// Define the tensor arena size
constexpr int kTensorArenaSize = 1024;

// Create a buffer to hold the model
namespace {
    // Place your model in this array (as generated by Arduino Create).
    extern const unsigned char g_model[];

    // Static memory buffer for TFLite runtime.
    uint8_t tensor_arena[kTensorArenaSize];
