tflite::ErrorReporter* error_reporter = nullptr;
const tflite::Model* model = tflite::GetModel(g_model);
static tflite::MicroInterpreter* interpreter;

void setup() {
    // Initialize serial communication
    Serial.begin(9600);

    // Setup the RGB color sensor
    Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);
    if (!tcs.begin()) {
        Serial.println("Failed to initialize the color sensor!");
        while (1); // Halt execution
    }

    // Initialize the error reporter and model validation
    static tflite::MicroErrorReporter micro_error_reporter;
    error_reporter = &micro_error_reporter;

    if (model->version() != TFLITE_SCHEMA_VERSION) {
        Serial.println("Model schema version does not match TensorFlow Lite runtime.");
        while (1);
    }

    // Instantiate the interpreter
    static tflite::MicroInterpreter static_interpreter(
      model, tflite::ops::micro::AllOpsResolver(), tensor_arena,
      kTensorArenaSize, error_reporter);
    interpreter = &static_interpreter;

    TfLiteStatus allocate_status = interpreter->AllocateTensors();
    if (allocate_status != kTfLiteOk) {
        Serial.println("AllocateTensors() failed");
        while (1);
    }
}

void loop() {
    // Initialize the sensor again for each read
    Adafruit_TCS34725 tcs(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

    if (!tcs.begin()) {
        Serial.println("Failed to initialize the color sensor!");
        while (1);
    }

    uint16_t r, g, b;
    tcs.getRawData(&r, &g, &b);

    // Convert raw values to floating point
    float red = static_cast<float>(r) / 65535.0f;
    float green = static_cast<float>(g) / 65535.0f;
    float blue = static_cast<float>(b) / 65535.0f;

    // Populate the input tensor
    TfLiteTensor* input_tensor = interpreter->input(0);
    float* input_data = input_tensor->data.f;
    input_data[0] = red;
    input_data[1] = green;
    input_data[2] = blue;

    // Run inference
    if (interpreter->Invoke() != kTfLiteOk) {
        Serial.println("Invoke failed");
        while (1);
    }

    // Process the output tensor
    TfLiteTensor* output_tensor = interpreter->output(0);
    const uint8_t* output_data = output_tensor->data.uint8;

    int max_index = 0;
    for (int i = 1; i < 3; ++i) {
        if (output_data[i] > output_data[max_index]) {
            max_index = i;
        }
    }

    // Output the classification result
    const char* classes[] = {"Apple", "Banana", "Orange"};
    Serial.print("Classified as: ");
    Serial.println(classes[max_index]);
}
