TfLiteTensor tensors[TENSOR_ARENA_SIZE];

void setup() {
  // Initialize serial communication
  Serial.begin(9600);

  // Phase 1.4: Load the Model
  error_reporter = tflite::ErrorReporter::CreateStderrReporter();
  model = tflite::GetModel(model_data);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    TF_LITE_REPORT_ERROR(error_reporter, "Model schema version mismatch!");
    while (true);
  }

  // Phase 1.5: Resolve Operators
  static tflite::MicroOpResolver<3> resolver;
  resolver.AddBuiltin(tflite::BuiltinOperator_DEPTHWISE_CONV_2D, 1);
  resolver.AddBuiltin(tflite::BuiltinOperator_CONV_2D, 1);
  resolver.AddBuiltin(tflite::BuiltinOperator_MAX_POOL_2D, 1);

  // Phase 1.6: Instantiate the Interpreter
  static tflite::MicroInterpreterStaticStorage<TENSOR_ARENA_SIZE> interpreter_storage;
  interpreter = new (interpreter_storage.storage) tflite::MicroInterpreter(model, resolver, tensors, TENSOR_ARENA_SIZE, error_reporter);

  // Phase 1.7: Allocate Memory
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Tensor allocation failed");
    while (true);
  }

  // Phase 1.8: Define Model Inputs
  input = interpreter->input(0);

  // Phase 1.9: Set Up Other Relevant Parts
  Adafruit_APDS9960 apds;

  if (!apds.begin()) {
    Serial.println(F("Failed to initialize APDS9960"));
    while (1);
  }
}

// Phase 2: Preprocessing

void loop() {
  // Phase 2.1: Sensor Setup
  uint16_t r, g, b;
  apds.readRGBC(&r, &g, &b);

  float red = static_cast<float>(r) / 1023.0;  // Normalize to [0, 1]
  float green = static_cast<float>(g) / 1023.0;
  float blue = static_cast<float>(b) / 1023.0;

  // Phase 2.2: Optional Feature Extraction
  // Assuming the raw RGB values are sufficient as model inputs

  // Phase 3: Inference

  // Phase 3.1: Data Copy
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Phase 3.2: Invoke Interpreter
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Inference failed");
    while (true);
  }

  // Phase 4: Postprocessing

  // Phase 4.1: Process Output
  const TfLiteTensor* output = interpreter->output(0);

  int prediction_index = 0;
  float max_score = -1.0f;

  for (int i = 0; i < output->dims->data[1]; ++i) {
    if (output->data.uint8[i] > max_score) {
      max_score = output->data.uint8[i];
      prediction_index = i;
    }
  }

  // Phase 4.2: Execute Application Behavior
  const char* classes[] = {"Apple", "Banana", "Orange"};
  Serial.print(F("Detected object: "));
  Serial.println(classes[prediction_index]);

  delay(1000); // Delay for stability
}
