    Serial.println("Failed to initialize APDS-9960!");
    while (1);
  }

  // Enable color sensor functionality
  apds.enableColor(true);
}

float* readSensorData(float* input_tensor) {
  uint16_t r, g, b;

  if (!apds.readColor(r, g, b)) {
    Serial.println("Failed to read color data");
    return nullptr;
  }

  // Normalize and scale sensor readings to [0.0, 1.0]
  *input_tensor = r / 1023.0f;  // Red channel
  *(input_tensor + 1) = g / 1023.0f;  // Green channel
  *(input_tensor + 2) = b / 1023.0f;  // Blue channel

