  // Initialize the APDS9960 sensor
  if (!apds.init()) {
    Serial.println("Failed to initialize APDS9960");
    return;
  }

  if (!apds.enableColorSensor()) {
    Serial.println("Failed to enable color sensor!");
    return;
  }

  // Load model into memory
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter->Report("Model provided is schema version %d not equal "
                           "to supported version %d.",
                           model->version(), TFLITE_SCHEMA_VERSION);
    return;
  }

  static tflite::MicroOpResolver<3> micro_op_resolver; // Adjust resolver if necessary

  // Build an interpreter
  const auto& allocation_params = tflite::MicroInterpreter::GetDefaultAllocationParams();
  std::unique_ptr<tflite::MicroInterpreter> interpreter_ptr(
      new tflite::MicroInterpreter(model, micro_op_resolver, tensor_arena,
                                   kTensorArenaSize, allocation_params, error_reporter));

  interpreter = interpreter_ptr->interpreter();

  // Allocate memory from the tensor_arena
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("Error during tensor allocation");
    return;
  }

  // Get input and output tensors.
  TfLiteTensor* input_tensor = interpreter->input(0);
  TfLiteTensor* output_tensor = interpreter->output(0);

  // Check input/output properties
  if (input_tensor->dims->data[0] != 1 || input_tensor->type != kTfLiteFloat32) {
    error_reporter->Report("Input tensor shape or type mismatch");
    return;
  }

  if (output_tensor->dims->data[0] != 1 || output_tensor->type != kTfLiteUInt8) {
    error_reporter->Report("Output tensor shape or type mismatch");
    return;
  }
}

void loop() {
  // Read color values
  uint16_t r, g, b, c; 
  if (apds.readColorData(&r, &g, &b)) {
    // Map the raw sensor data to a range [0.0 - 1.0]
    float input[3] = {static_cast<float>(r) / 1023.0f, static_cast<float>(g) / 1023.0f, static_cast<float>(b) / 1023.0f};

    // Copy data to the input tensor
    memcpy(input_tensor->data.f, input, sizeof(input));

    // Run inference
    TfLiteStatus invoke_status = interpreter->Invoke();
    if (invoke_status != kTfLiteOk) {
      error_reporter->Report("Error during model invocation");
      return;
    }

    // Retrieve and process the output
    uint8_t* output_data = output_tensor->data.uint8;
    int max_index = 0;
    for (int i = 1; i < 3; ++i) {
      if (output_data[i] > output_data[max_index]) {
        max_index = i;
      }
    }

    // Output the result
    Serial.print("Detected: ");
    Serial.println(CLASS_NAMES[max_index]);

    delay(500); // Adjust as needed for sensor read frequency and application behavior.
  } else {
    error_reporter->Report("Failed to read color data");
  }
}
