```cpp
#include <TensorFlowLite.h>
#include <Adafruit_APDS9960.h>
#include "model.h"

// Define the tensor arena size
constexpr int kTensorArenaSize = 2048;

// Declare variables
tflite::ErrorReporter* error_reporter;
const tflite::Model* model = nullptr;
TfLiteInterpreter* interpreter = nullptr;
float input_data[3];

// Function to initialize peripherals and components
void setupPeripherals() {
    // Initialize serial communication
    Serial.begin(9600);

    // Initialize the color sensor
    Adafruit_APDS9960 apds = Adafruit_APDS9960();
    if (!apds.begin()) {
        Serial.println("Failed to initialize APDS-9960 sensor!");
        while (1);
    }
}

// Function to perform inference
void inferColor(float red, float green, float blue) {
    input_data[0] = red;
    input_data[1] = green;
    input_data[2] = blue;

    // Copy data into the interpreter's input tensor
    TfLiteTensor* input_tensor = interpreter->input(0);
    float* input_ptr = input_tensor->data.f;
    for (size_t i = 0; i < 3; ++i) {
        input_ptr[i] = input_data[i];
    }

    // Invoke the interpreter to run inference
    if (interpreter->Invoke() != kTfLiteOk) {
        Serial.println("Failed to invoke!");
        return;
    }

    // Retrieve the output tensor and interpret results
    TfLiteTensor* output_tensor = interpreter->output(0);
    const uint8_t* output_ptr = output_tensor->data.uint8;

    // Map output to class names
    const char* classes[] = {"Apple", "Banana", "Orange"};
    Serial.print("Detected object: ");
    for (size_t i = 0; i < 3; ++i) {
        if (output_ptr[i] > 128) {  // Assuming a threshold for binary classification
            Serial.println(classes[i]);
            break;
        }
    }
}

void setup() {
    error_reporter = tflite::ErrorReporter::NewLocal(tflite::File::FILE_STDOUT);
    model = tflite::GetModel(model_data);

    if (model->version() != TFLITE_SCHEMA_VERSION) {
        Serial.println("Model schema version does not match TensorFlow Lite runtime.");
        while (1);
    }

    static tflite::MicroErrorReporter micro_error_reporter;
    error_reporter = &micro_error_reporter;

    // Allocate memory from the tensor_arena for the interpreter's tensors
    static uint8_t tensor_arena[kTensorArenaSize];
    tflite::ops::micro::AllOpsResolver resolver;

    interpreter = new TfLiteInterpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

    if (interpreter->AllocateTensors() != kTfLiteOk) {
        Serial.println("Failed to allocate tensors!");
        while (1);
    }

    setupPeripherals();
}

void loop() {
    Adafruit_APDS9960 apds = Adafruit_APDS9960();

    // Check if the color sensor is ready
    if (apds.colorDataReady()) {
        uint16_t r, g, b;
        apds.readColor(&r, &g, &b);

        // Normalize RGB values to [0, 1]
        float red = r / 1023.0f;
        float green = g / 1023.0f;
        float blue = b / 1023.0f;

        inferColor(red, green, blue);
    }

    delay(1000); // Wait for a second before the next reading
}
```

