        return false;
    }

    return true;
}

// Function to initialize the interpreter
bool InitInterpreter() {
    static tflite::ops::micro::AllOpsResolver resolver;

    // Instantiate an interpreter with the model, and use it for inference.
    interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena,
                                               kTensorArenaSize, error_reporter);
    if (!interpreter) {
        TF_LITE_REPORT_ERROR(error_reporter, "Failed to allocate memory for "
                                   "TfLite interpreter\n");
        return false;
    }

    // Allocate memory from the tensor arena for the model's tensors.
    TfLiteStatus allocate_status = interpreter->AllocateTensors();
    if (allocate_status != kTfLiteOk) {
        TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed\n");
        delete interpreter;  // Clean up
        return false;
    }

    return true;
}

void setup() {
