            if (output_tensor->type == kTfLiteUInt8) {
                uint8_t* output_data = reinterpret_cast<uint8_t*>(output_tensor->data.data);
                int max_index = 0;
                for (size_t i = 1; i < 3; ++i) {
                    if (output_data[i] > output_data[max_index]) {
                        max_index = i;
                    }
