                    case 1:
                        Serial.println("🍌");
                        break;
                    case 2:
                        Serial.println("🍊");
                        break;
                    default:
                        Serial.println("❓");
                }
            } else {
                TF_LITE_REPORT_ERROR(error_reporter, "Unexpected output tensor type\n");
            }
        }
    }

    delay(100);
}
