```cpp
#include <TensorFlowLite.h>
#include "model.h"
#include "Adafruit_TCS34725.h"
#include "Wire.h"

// Global variables for TensorFlow Lite Micro
tflite::ErrorReporter* error_reporter = nullptr;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;

// Sensor setup
Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

// Define tensor arena for TensorFlow Lite Micro
constexpr int kTensorArenaSize = 2048;
uint8_t tensor_arena[kTensorArenaSize];

void setup() {
  // Initialize serial communication
  Serial.begin(9600);

  // Initialize error reporter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load the model and check for validity
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    TF_LITE_REPORT_ERROR(error_reporter, "Model schema version mismatch!");
    while (1) { delay(10); }
  }

  // Initialize the op resolver and interpreter
  static tflite::ops::micro::AllOpsResolver resolver;
  static uint8_t tensor_arena[kTensorArenaSize];
  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

  // Allocate memory from the tensor arena for the model's tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Memory allocation failed");
    while (1) { delay(10); }
  }

  // Setup color sensor
  if (!tcs.begin()) {
    Serial.println("No TCS34725 found ... check your connections");
    while (1) { delay(5000); }
  }
}

void loop() {
  // Read RGB values from the sensor
  uint16_t clear, red, green, blue;
  tcs.getRawData(&red, &green, &blue, &clear);

  // Normalize and scale the RGB values to fit model input requirements
  float normalizedInput[3] = {
    static_cast<float>(red) / clear,
    static_cast<float>(green) / clear,
    static_cast<float>(blue) / clear
  };

  // Copy the data into the input tensor
  TfLiteTensor* input_tensor = interpreter->input(0);
  float* flat_input = input_tensor->data.f;
  memcpy(flat_input, normalizedInput, sizeof(normalizedInput));

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed");
    return;
  }

  // Process the output
  TfLiteTensor* output_tensor = interpreter->output(0);
  uint8_t* flat_output = reinterpret_cast<uint8_t*>(output_tensor->data.uint8);

  int max_index = 0;
  float max_value = -1.0f;

  for (int i = 0; i < 3; ++i) {
    if (flat_output[i] > max_value) {
      max_value = flat_output[i];
      max_index = i;
    }
  }

  // Output the classification result
  const char* classes[] = {"Apple", "Banana", "Orange"};
  Serial.print(classes[max_index]);
  switch (max_index) {
    case 0: Serial.write(128522); break; // 🍎
    case 1: Serial.write(127800); break; // 🍌
    case 2: Serial.write(127942); break; // 🍊
  }
  Serial.println();

  delay(1000);
}
```

