#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "model.h"

// Include Adafruit sensor libraries and Wire library for communication
#include <Adafruit_TCS34725.h>
#include <Wire.h>

namespace {
  tflite::ErrorReporter* error_reporter = nullptr;
}

constexpr int kTensorArenaSize = 2048;
uint8_t tensor_arena[kTensorArenaSize];

TfLiteTensor* input_tensor = nullptr;
TfLiteTensor* output_tensor = nullptr;

// Replace 'tflite::MicroInterpreter' with the correct type for Arduino Nano 33 BLE Sense
using tflite::MicroInterpreter; 

void PrintClassification(float* results) {
  if (results[0] > results[1] && results[0] > results[2]) {
    Serial.println("\U0001F34E"); // Apple Emoji 🍎
  } else if (results[1] > results[0] && results[1] > results[2]) {
    Serial.println("\U0001F34C"); // Banana Emoji 🍌
  } else {
    Serial.println("\U0001F34F"); // Orange Emoji 🍏
  }
}

void setup() {
  // Initialize serial communication for debugging and output
  Serial.begin(9600);

  // TensorFlow Lite Micro initialization
  error_reporter = tflite::MicroErrorReporter();

  const tflite::Model* model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    TF_LITE_REPORT_ERROR(error_reporter, "Model provided is schema version %d not equal supported version %d.",
                         model->version(), TFLITE_SCHEMA_VERSION);
    return;
  }

  static tflite::MicroInterpreter static_interpreter(
      model, tflite::AllOpsResolver(), tensor_arena, kTensorArenaSize,
      error_reporter);

  interpreter = &static_interpreter;

  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed");
    return;
  }

  input_tensor = interpreter->input(0);
  output_tensor = interpreter->output(0);

  // Initialize the color sensor
  Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

  if (tcs.begin()) {
    Serial.println("TCS34725 color sensor found.");
  } else {
    Serial.println("No TCS34725 found ... check your connections");
    while (1); // Halt system
  }
}

void loop() {
  float red, green, blue;

  // Read data from the color sensor
  if (tcs.getRawData(&red, &green, &blue)) {
    input_tensor->data.f[0] = red / 65536.0;
    input_tensor->data.f[1] = green / 65536.0;
    input_tensor->data.f[2] = blue / 65536.0;

    // Run inference
    TfLiteStatus invoke_status = interpreter->Invoke();
    if (invoke_status != kTfLiteOk) {
      TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed");
    }

    // Process the output and print the classification result
    float* probabilities = output_tensor->data.f;
    PrintClassification(probabilities);
  } else {
    Serial.println("Failed to read data from color sensor.");
  }

  delay(500); // Delay between readings
}
```

