#include <Arduino_LSM9DS1.h>
#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/kernels/micro_ops.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "model.h"

// Serial communication for output
#define BAUD_RATE 9600

// Tensor arena size: Adjust based on model requirements and memory availability.
constexpr int tensor_arena_size = 1024;
uint8_t tensor_arena[tensor_arena_size];

// Error reporting object
tflite::MicroErrorReporter micro_error_reporter;

// Used to hold the model
const tflite::Model* model = nullptr;

// Micro interpreter instance
static tflite::MicroInterpreter static_interpreter(
    model, tflite::AllOpsResolver(), tensor_arena,
    tensor_arena_size, &micro_error_reporter);

tflite::MicroInterpreter* interpreter = &static_interpreter;

// Used to get info about the input and output tensors.
TfLiteTensor* input_tensor;
TfLiteTensor* output_tensor;

void setup() {
  Serial.begin(BAUD_RATE);

  // Initialize IMU
  if (!IMU.begin()) {
    Serial.println("Failed to initialize IMU!");
    while (1);
  }

  // Obtain pointers to the model's input and output tensors.
  input_tensor = interpreter->input(0);
  output_tensor = interpreter->output(0);

  // Load model into memory
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match TensorFlow Lite runtime.");
    while (1);
  }

  // Initialize the interpreter
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    Serial.println("Tensor allocation failed");
    while (1);
  }
}

void loop() {
  uint16_t red, green, blue;

  // Read color sensor values
  sensors_event_t event;
  colorSensor.getEvent(&event);

  red = map(event.red, 0, 1023, 0, 255);
  green = map(event.green, 0, 1023, 0, 255);
  blue = map(event.blue, 0, 1023, 0, 255);

  // Normalize sensor values to range [0.0, 1.0]
  float normalized_input[3] = {
    static_cast<float>(red) / 255.0,
    static_cast<float>(green) / 255.0,
    static_cast<float>(blue) / 255.0
  };

  // Copy input to the model's input tensor
  for (size_t i = 0; i < 3; ++i) {
    input_tensor->data.f[i] = normalized_input[i];
  }

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    Serial.println("Failed to invoke!");
    while (1);
  }

  // Retrieve the classification result from the output tensor
  uint8_t predicted_class_index = output_tensor->data.uint8[0];

