#include <TensorFlowLite.h>
#include "Arduino_TensorFlowLite_Arduino_Nano_33_BLE_Sense.h"
#include "Adafruit_TCS34725.h"

// Include the model header file
#include "model.h"

// Constants for RGB color sensor
#define COLOR_SENSOR_MODEL TCS34725_INTEGRATIONTIME_50MS
#define COLOR_SENSOR_GAIN TCS34725_GAIN_4X

// Define tensor arena size
constexpr int kTensorArenaSize = 1000;

// Declare TensorFlow Lite Micro variables
tflite::ErrorReporter* error_reporter;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;
TfLiteTensor* input_tensor = nullptr;
TfLiteTensor* output_tensor = nullptr;
uint8_t tensor_arena[kTensorArenaSize];

// Define classes for classification
const char* CLASS_NAMES[] = {"Apple", "Banana", "Orange"};

Adafruit_TCS34725 tcs = Adafruit_TCS34725(COLOR_SENSOR_MODEL, COLOR_SENSOR_GAIN);

void setup() {
  // Initialize Serial communication
  Serial.begin(9600);

  // Initialize the color sensor
  if (tcs.begin()) {
    Serial.println("Color sensor initialized.");
  } else {
    Serial.println("Error initializing color sensor!");
  }

  // Set up TensorFlow Lite interpreter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version mismatch!");
    return;
  }

  static tflite::ops::micro::AllOpsResolver resolver;

  // Create an interpreter to run the inference
  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena,
                                            kTensorArenaSize, error_reporter);
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    return;
  }

  // Get pointers to input and output tensors
  input_tensor = interpreter->input(0);
  output_tensor = interpreter->output(0);
}

void loop() {
  // Read RGB values from the color sensor
  uint16_t r, g, b, c;
  if (tcs.getRawData(&r, &g, &b, &c)) {
    float red = r / (float)c;
    float green = g / (float)c;
    float blue = b / (float)c;

    // Normalize and copy the input data into the model's input tensor
    input_tensor->data.f[0] = red;
    input_tensor->data.f[1] = green;
    input_tensor->data.f[2] = blue;

    // Invoke the interpreter to run inference
    if (interpreter->Invoke() == kTfLiteOk) {
      // Process the output tensor and determine the class with highest probability
      int best_class = 0;
      float max_score = -1.0f;
      for (int i = 0; i < 3; ++i) { // Assuming 3 classes as per model specifications
        if (output_tensor->data.uint8[i] > max_score) {
          max_score = output_tensor->data.uint8[i];
          best_class = i;
        }
      }

      // Output the classification result via Serial in Unicode emoji format
      Serial.print("Detected: ");
      Serial.println(CLASS_NAMES[best_class]);
    } else {
      Serial.println("Failed to invoke model!");
    }
  }

  delay(1000); // Run inference every second
}
