#include "TensorFlowLite.h"
#include "model.h"
#include <Adafruit_TCS34725.h>
#include <Arduino_LMIC.h>
#include <BLEDevice.h>
#include <Wire.h>

// Define the tensor arena size as specified
constexpr int kTensorArenaSize = 2048;

// Declare TensorFlow Lite Micro variables
tflite::ErrorReporter* error_reporter;
const tflite::Model* model;
tflite::MicroInterpreter* interpreter;
TfLiteTensor* input_tensor;
uint8_t tensor_arena[kTensorArenaSize];

// Create an instance of the TCS34725 color sensor
Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);

void setup() {
  // Initialize serial communication for debugging
  Serial.begin(9600);

  // Set up the error reporter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Load model and create interpreter
  model = tflite::GetModel(model_data);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version mismatch!");
    while (1) { delay(1000); }
  }

  static tflite::MicroOpResolver<3> micro_op_resolver;

  // Initialize the interpreter with the model, resolver, tensor arena and error reporter
  interpreter = new tflite::MicroInterpreter(model, micro_op_resolver, tensor_arena, kTensorArenaSize, error_reporter);
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1) { delay(1000); }
  }

  // Retrieve the input tensor
  input_tensor = interpreter->input(0);

  // Initialize the color sensor
  if (tcs.begin()) {
    Serial.println("TCS34725 Color Sensor Found");
  } else {
    Serial.println("No TCS34725 found ... check your connections");
    while (1) { delay(1000); }
  }
}

void loop() {
  // Read RGB values from the color sensor
  float r, g, b, c;
  tcs.getRawData(&r, &g, &b, &c);

  // Convert to scale of 0.0 to 1.0 (as in dataset)
  r /= 256.0;
  g /= 256.0;
  b /= 256.0;

  // Copy RGB values into the input tensor
  memcpy(input_tensor->data.f, &r, sizeof(float));
  memcpy(input_tensor->data.f + 1, &g, sizeof(float));
  memcpy(input_tensor->data.f + 2, &b, sizeof(float));

  // Run inference
  if (interpreter->Invoke() != kTfLiteOk) {
    Serial.println("Failed to invoke!");
    while (1) { delay(1000); }
  }

  // Retrieve the output tensor
  TfLiteTensor* output_tensor = interpreter->output(0);

  // Get classification result
  int predicted_class_index = -1;
  float max_score = 0.0f;
  for (int i = 0; i < 3; ++i) {
    if (output_tensor->data.uint8[i] > max_score) {
      max_score = output_tensor->data.uint8[i];
      predicted_class_index = i;
    }
  }

  // Map class index to emoji
  const char* emojis[] = {U"🍎", U"🍌", U"🍊"};
  if (predicted_class_index >= 0 && predicted_class_index < 3) {
    Serial.println(String((const char*)emojis[predicted_class_index]));
  } else {
    Serial.println("Unknown class");
  }

  // Wait before next read
  delay(1000);
}
