    if (tcs.getRGB(&red, &green, &blue, &clear)) {
        float r = red / 65535.0f;
        float g = green / 65535.0f;
        float b = blue / 65535.0f;

        // Copy the input data to the input tensor
        TfLiteTensor* input = tflite::GetInput(interpreter, 0);
        memcpy(input->data.f, &r, sizeof(float));
        memcpy((float*)input->data.f + 1, &g, sizeof(float));
        memcpy((float*)input->data.f + 2, &b, sizeof(float));

        // Run inference
        if (interpreter.Invoke() != kTfLiteOk) {
            Serial.println("Failed to invoke!");
            while (true);
        }

        // Get the result from output tensor
        TfLiteTensor* output = tflite::GetOutput(interpreter, 0);
