void setup() {
    Serial.begin(9600);

    Adafruit_TCS34725 tcs(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);
    if (tcs.begin()) {
        Serial.println("TCS34725 found");
    } else {
        Serial.println("No TCS34725 sensor found ... check your connections");
    }

    static tflite::MicroErrorReporter micro_error_reporter;
    const tflite::Model* model = ::g_model;  // Correctly reference the global variable
    if (model->version() != TFLITE_SCHEMA_VERSION) {
        Serial.println("Model schema version does not match TensorFlow Lite runtime.");
        while (true);
    }

    static tflite::AllOpsResolver resolver;
    static tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, tensor_arena_size, &micro_error_reporter);

    if (interpreter.AllocateTensors() != kTfLiteOk) {
        Serial.println("Failed to allocate tensors!");
        while (true);
    }

    const char* emojis[] = {"🍎", "🍌", "🍊"};
}

void loop() {
    Adafruit_TCS34725 tcs(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);
    uint16_t clear, red, green, blue;

    if (tcs.getRawData(&red, &green, &blue, &clear)) {  // Correct type conversion
        float r = static_cast<float>(red) / clear;
        float g = static_cast<float>(green) / clear;
        float b = static_cast<float>(blue) / clear;

        TfLiteTensor* input = interpreter.input(0);
        float* input_ptr = input->data.f;
        input_ptr[0] = r;
        input_ptr[1] = g;
        input_ptr[2] = b;

        if (interpreter.Invoke() == kTfLiteOk) {
            TfLiteTensor* output = interpreter.output(0);
            uint8_t class_idx = output->data.uint8[0];

            Serial.print("Classified as: ");
            Serial.println(emojis[class_idx]);
        } else {
            Serial.println("Failed to invoke interpreter");
        }
    }

    delay(1000);  // Delay for a second before the next reading
}
