#include <TensorFlowLite.h>
#include "model.h"
#include <Arduino_LSM9DS1.h>
#include <arduinoFFT.h>

// TensorFlow Lite specific declarations
static tflite::ErrorReporter* error_reporter;
static const tflite::Model* model;
static tflite::MicroInterpreter* interpreter;
static TfLiteTensor* input;
static uint8_t tensor_arena[2048]; // 2KB tensor arena as specified

// RGB color sensor setup
const int redPin = A0;   // Adjust pin numbers according to your hardware setup
const int greenPin = A1;
const int bluePin = A2;

void setup() {
  Serial.begin(9600);

  // Initialize TensorFlow Lite components
  error_reporter = tflite::MicroErrorReporter::NewLogTo(&std::cout);
  model = tflite::GetModel(model_data);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model provided is schema version mismatch!");
    while (1) { delay(1000); }
  }

  static tflite::MicroOpResolver<3> resolver;
  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena,
                                             sizeof(tensor_arena), error_reporter);
  interpreter->AllocateTensors();

  input = interpreter->input(0);

  // Initialize color sensor
  pinMode(redPin, INPUT);
  pinMode(greenPin, INPUT);
  pinMode(bluePin, INPUT);
}

void loop() {
  // Read RGB values from the sensor
  int redValue = analogRead(redPin) / 4.0;
  int greenValue = analogRead(greenPin) / 4.0;
  int blueValue = analogRead(bluePin) / 4.0;

  float inputData[3] = {redValue / 1023.0, greenValue / 1023.0, blueValue / 1023.0};

  // Copy input data to the model's input tensor
  for (size_t i = 0; i < 3; ++i) {
    ((float*)input->data.f)[i] = inputData[i];
  }

  // Run inference
  interpreter->Invoke();

  // Retrieve output and determine class
  TfLiteTensor* output = interpreter->output(0);
  int predictedClassIndex = -1;
  float maxScore = -1.0;

  for (size_t i = 0; i < 3; ++i) {
    if (((uint8_t*)output->data.uint8)[i] > maxScore) {
      maxScore = ((uint8_t*)output->data.uint8)[i];
      predictedClassIndex = i;
    }
  }

  // Map the class index to a label and send it over serial
  const char* classLabels[] = {"Apple", "Banana", "Orange"};
  if (predictedClassIndex >= 0 && predictedClassIndex < 3) {
    Serial.print("Detected: ");
    Serial.println(classLabels[predictedClassIndex]);

    // Print corresponding emoji as a visual representation
    switch (predictedClassIndex) {
      case 0:
        Serial.write(0x1F34E); // Apple Emoji
        break;
      case 1:
        Serial.write(0x1F34C); // Banana Emoji
        break;
      case 2:
        Serial.write(0x1F34F); // Orange Emoji
        break;
    }
  }

  delay(1000);  // Delay for stability and readability of the output
}
