#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/schema/schema_generated.h>
#include <tensorflow/lite/version.h>
#include <Arduino_LSM9DS1.h>  // Assuming color sensor is part of the LSM9DS1 package for this setup
#include "model.h"            // Include your trained TFLite model header file

constexpr int kTensorArenaSize = 2 * 1024;  // Size of the tensor arena in bytes

// Define application-specific constants
const char* classNames[] = {"Apple", "Banana", "Orange"};

// Create a buffer to hold inference data
alignas(16) uint8_t tensor_arena[kTensorArenaSize];

// Declare variables for TensorFlow Lite Micro components
tflite::ErrorReporter* error_reporter = nullptr;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;

// Placeholder to hold input data and output results
TfLiteTensor* input = nullptr;
TfLiteTensor* output = nullptr;

void setup() {
  // Initialize serial communication for debugging
  Serial.begin(9600);

  // Setup color sensor (assuming integrated with LSM9DS1)
  if (!IMU.begin()) {
    Serial.println("Failed to initialize IMU!");
    while (1);
  }

  // Allocate error reporter
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Map the model into a usable data structure
