  // Read color values from the sensor
  if (IMU.colorSensor().readColor(redValue, greenValue, blueValue)) {
    // Normalize the input to match model expectations
    const float* input = interpreter->input(0);
    input[0] = redValue;
    input[1] = greenValue;
    input[2] = blueValue;

    // Run inference
    TfLiteStatus invoke_status = interpreter->Invoke();
    if (invoke_status != kTfLiteOk) {
      TF_LITE_REPORT_ERROR(error_reporter, "Failed to invoke interpreter.");
    }

    // Get the output from the model
    const float* output = interpreter->output(0);
    int maxIndex = 0;
    for (int i = 1; i < 3; ++i) {
      if (output[i] > output[maxIndex]) {
        maxIndex = i;
      }
    }

    // Map the index to a class name
    const char* classNames[] = {"Apple", "Banana", "Orange"};
    Serial.print("Detected: ");
    Serial.println(classNames[maxIndex]);

    // Output corresponding Unicode emoji
    switch (maxIndex) {
      case 0:
        Serial.println("\xF0\x9F\x8C\x8D"); // 🌍 for Apple
        break;
      case 1:
        Serial.println("\xF0\x9F\x8C\x85"); // 🌅 for Banana
        break;
      case 2:
        Serial.println("\xF0\x9F\x90\xA5"); // 🐥 for Orange
        break;
    }
  }

  delay(1000); // Delay before next reading
}
