```cpp
#include <Arduino.h>
#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <Adafruit_APDS9960.h>
#include <Wire.h>

// Include the model file
#include "model.h"

// TensorFlow Lite Micro objects
namespace {
  constexpr int kTensorArenaSize = 1024;
  alignas(16) uint8_t tensor_arena[kTensorArenaSize];

  tflite::ErrorReporter* error_reporter = nullptr;
  const tflite::Model* model = nullptr;
  tflite::MicroInterpreter* interpreter = nullptr;

  TfLiteStatus AllocateTensors() {
    return interpreter->AllocateTensors();
  }
}

// Sensor setup
Adafruit_APDS9960 apds = Adafruit_APDS9960();

void setup() {
  // Initialize serial communication
  Serial.begin(9600);

  // Initialize the APDS-9960 sensor
  if (!apds.init()) {
    Serial.println("Failed to initialize APDS-9960");
    while (1);
  }

  // Start the color sensor
  if (!apds.enableColorSensor()) {
    Serial.println("Failed to enable color sensor");
    while (1);
  }

  // Initialize TensorFlow Lite Micro objects
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  model = tflite::GetModel(model_data);

  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version mismatch!");
    while (1);
  }

  static tflite::AllOpsResolver resolver;

  interpreter = new tflite::MicroInterpreter(
      model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

  TfLiteStatus allocate_status = AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1);
  }
}

void loop() {
  uint16_t red, green, blue;

  // Read color data
  apds.readColor(&red, &green, &blue);

  float input_data[3] = {static_cast<float>(red) / 1024.0f,
                         static_cast<float>(green) / 1024.0f,
                         static_cast<float>(blue) / 1024.0f};

  // Get pointer to the model's input tensor
  TfLiteTensor* input_tensor = interpreter->input(0);

  // Copy data into the input tensor
  float* input_ptr = input_tensor->data.f;
  memcpy(input_ptr, input_data, sizeof(input_data));

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    Serial.println("Failed to invoke!");
    while (1);
  }

  // Get pointer to the model's output tensor
  const TfLiteTensor* output_tensor = interpreter->output(0);

  uint8_t* output_ptr = output_tensor->data.uint8;

  // Determine classification based on the highest score in the output tensor
  int max_index = -1;
  float max_score = 0.0f;
  for (int i = 0; i < 3; ++i) {
    if (output_ptr[i] > max_score) {
      max_score = static_cast<float>(output_ptr[i]);
      max_index = i;
    }
  }

  // Define class labels
  const char* classes[] = {"Apple", "Banana", "Orange"};

  // Output the result as an emoji to Serial
  if (max_index >= 0 && max_index < 3) {
    switch (max_index) {
      case 0:
        Serial.println("🍎");
        break;
      case 1:
        Serial.println("🍌");
        break;
      case 2:
        Serial.println("🍊");
        break;
    }
  }

  // Small delay before the next reading
  delay(500);
}
```

