  }

  // Initialize the interpreter
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Tensor allocation failed");
    while (1) { continue; }
  }

  // Get pointers to input and output tensors
  input = interpreter->input(0);
  output = interpreter->output(0);

  // Initialize the color sensor
  if (!tcs.begin()) {
    Serial.println("No TCS34725 found ... check your connections");
    while (1) { continue; }
  }

  tcs.setInterrupt(false); // Turn off interrupt

  // Allow time for device to settle
  delay(500);
}

void loop() {
  float r, g, b;
  uint16_t clear;

  // Read color values from the sensor
  tcs.getRawData(&r, &g, &b, &clear);

  // Convert raw data to RGB floats (0.0 - 1.0)
  float red = r / (float) clear;
  float green = g / (float) clear;
  float blue = b / (float) clear;

  // Copy input data into the tensor
  memcpy(input->data.f, &red, sizeof(float));
  memcpy((void*)((char*)input->data.f + sizeof(float)), &green, sizeof(float));
  memcpy((void*)((char*)input->data.f + 2 * sizeof(float)), &blue, sizeof(float));

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed");
    while (1) { continue; }
  }

  // Process output
  uint8_t result_index = output->data.uint8[0];
  String result;

  switch(result_index) {
    case 0:
      result = "🍎 Apple";
      break;
    case 1:
      result = "🍌 Banana";
      break;
    case 2:
      result = "🍊 Orange";
      break;
    default:
      result = "Unknown";
      break;
  }

  // Output the classification result
  Serial.println(result);

  // Allow some time before the next reading
  delay(1000);
}
