#include "model.h"
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/kernels/micro_ops.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"

#include <Wire.h>
#include "Adafruit_TCS34725.h"

// Tensor arena size
constexpr int kTensorArenaSize = 2048;

// Model data array (replace with your actual model data)
extern const unsigned char model_data[];

// Define the tensor arena buffer
alignas(16) uint8_t tensor_arena[kTensorArenaSize];

// Error reporter
::tflite::MicroErrorReporter micro_error_reporter;
::tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Tensorflow Lite interpreter
static tflite::MicroInterpreter static_interpreter(
    model, // Pointer to the model data
    tensor_arena, // Pointer to the tensor arena
    kTensorArenaSize, // Size of the tensor arena
    ops_resolver,  // Operations resolver
    error_reporter);

// Hold reference to the interpreter
tflite::MicroInterpreter* interpreter = &static_interpreter;

// Model pointer
const tflite::Model* model = nullptr;

// OpResolver
using namespace tflite;
OpResolver<4, 1> ops_resolver;

// Input and output pointers
TfLiteTensor* input = nullptr;
TfLiteTensor* output = nullptr;

void setup() {
    // Initialize serial communication for debugging purposes
    Serial.begin(9600);

    // Initialize color sensor
    Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);
    if (tcs.begin()) {
        Serial.println("TCS34725 found.");
    } else {
        Serial.println("No TCS34725 sensor found ... check your connections");
    }

    // Load the model
    model = tflite::GetModel(model_data);
    if (model->version() != TFLITE_SCHEMA_VERSION) {
        error_reporter->Report(
            "Model provided is schema version %d not equal "
            "to supported version %d.",
            model->version(), TFLITE_SCHEMA_VERSION);
        return;
    }

    // Resolve operators
    ops_resolver.AddBuiltin(TfLiteBuiltinActivations, 1);
    ops_resolver.AddBuiltin(TfLiteBuiltinLogistic, 1);
    ops_resolver.AddBuiltin(TfLiteBuiltinConv2D, 3);

    // Instantiate the interpreter
    static tflite::MicroErrorReporter micro_error_reporter;
    tflite::MicroInterpreter intp(model, ops_resolver, tensor_arena,
                                  kTensorArenaSize, &micro_error_reporter);

    // Allocate memory from the tensor arena for the model's tensors
    TfLiteStatus allocate_status = intp.AllocateTensors();
    if (allocate_status != kTfLiteOk) {
        Serial.println("AllocateTensors() failed");
        return;
    }

    // Obtain pointers to the input and output tensors
    input = intp.input(0);
    output = intp.output(0);

    // Check tensor shapes
    const int tensor_rank = tflite::micro::ShapeUtils::Rank(input->dims);
    if (tensor_rank != 2) {
        Serial.println("Input tensor rank should be 2");
        return;
    }
}

void loop() {
    // Read data from the color sensor
    uint16_t clear, red, green, blue;
    Adafruit_TCS34725 tcs = Adafruit_TCS34725(TCS34725_INTEGRATIONTIME_50MS, TCS34725_GAIN_4X);
    if (tcs.getRawData(&red, &green, &blue, &clear)) {
        // Convert to float and scale to [0, 1]
        input->data.f[0] = red / clear;
        input->data.f[1] = green / clear;
        input->data.f[2] = blue / clear;

        // Run inference
        TfLiteStatus invoke_status = interpreter->Invoke();
        if (invoke_status != kTfLiteOk) {
            Serial.println("Invoke failed");
            return;
        }

        // Post-process the output
        int max_index = 0;
        float max_value = output->data.uint8[max_index];
        for (int i = 1; i < 3; ++i) {
            if (output->data.uint8[i] > max_value) {
                max_value = output->data.uint8[i];
                max_index = i;
            }
        }

        // Output the result
        switch(max_index) {
            case 0:
                Serial.println("🍎 Apple");
                break;
            case 1:
                Serial.println("🍌 Banana");
                break;
            case 2:
                Serial.println("🍊 Orange");
                break;
        }
    }

    delay(1000); // Wait for a second before the next loop iteration
}
